import{_ as p,o as e,c as d,ag as r}from"./chunks/framework.ePeAWSvT.js";const a="/images/image_027.png",i="/images/image_028.png",n="/images/image_029.png",o="/images/image_030.png",s="/images/image_031.png",g="/images/image_032.png",m="/images/image_033.png",c="/images/image_034.png",l="/images/image_035.png",h="/images/image_036.png",A="/images/image_037.png",P="/images/image_038.png",S="/images/image_039.png",_="/images/image_040.png",b="/images/image_041.png",E="/images/image_042.png",N="/images/image_043.png",D="/images/image_044.png",I="/images/image_045.png",L="/images/image_046.png",u="/images/image_047.png",R="/images/image_048.png",V="/images/image_049.png",C="/images/image_050.png",M="/images/image_051.png",U="/images/image_052.png",T="/images/image_053.png",y="/images/image_054.png",w="/images/image_055.png",k="/images/image_056.png",f="/images/image_057.png",q="/images/image_058.png",x="/images/image_059.png",G="/images/image_060.png",v="/images/image_061.png",X="/images/image_062.png",O="/images/image_063.png",B="/images/image_064.png",F="/images/image_065.png",H="/images/image_066.png",W="/images/image_067.png",K="/images/image_068.png",z="/images/image_069.png",$="/images/image_070.png",j="/images/image_071.png",J="/images/image_072.png",Q="/images/image_073.png",Y="/images/image_074.png",Z="/images/image_075.png",tt="/images/image_076.png",pt="/images/image_077.png",et="/images/image_078.png",dt="/images/image_079.png",rt="/images/image_080.png",at="/images/image_081.png",it="/images/image_082.png",nt="/images/image_083.png",ot="/images/image_084.png",st="/images/image_085.png",gt="/images/image_086.png",mt="/images/image_087.png",ct="/images/image_088.png",lt="/images/image_089.png",ht="/images/image_090.png",At="/images/image_091.png",Pt="/images/image_092.png",St="/images/image_093.png",_t="/images/image_094.png",bt="/images/image_095.png",Et="/images/image_096.png",Nt="/images/image_097.png",Dt="/images/image_098.png",It="/images/image_099.png",Lt="/images/image_100.png",ut="/images/image_101.png",Rt="/images/image_102.png",Vt="/images/image_103.png",Ct="/images/image_104.png",Mt="/images/image_105.png",Ut="/images/image_106.png",Tt="/images/image_107.png",yt="/images/image_108.png",wt="/images/image_109.png",kt="/images/image_110.png",ft="/images/image_111.png",qt="/images/image_112.png",xt="/images/image_113.png",Gt="/images/image_114.png",vt="/images/image_115.png",Xt="/images/image_116.png",Ot="/images/image_117.png",Bt="/images/image_118.png",Ft="/images/image_119.png",Ht="/images/image_120.png",Wt="/images/image_121.png",Kt="/images/image_122.png",zt="/images/image_123.png",$t="/images/image_124.png",jt="/images/image_125.png",Jt="/images/image_126.png",Qt="/images/image_127.png",Yt="/images/image_128.png",Zt="/images/image_129.png",tp="/images/image_130.png",pp="/images/image_131.png",ep="/images/image_132.png",dp="/images/image_133.png",rp="/images/image_134.png",ap="/images/image_135.png",ip="/images/image_136.png",np="/images/image_137.png",op="/images/image_138.png",sp="/images/image_139.png",gp="/images/image_140.png",mp="/images/image_141.png",cp="/images/image_142.png",lp="/images/image_143.png",hp="/images/image_144.png",Ap="/images/image_145.png",Pp="/images/image_146.png",Sp="/images/image_147.png",_p="/images/image_148.png",Vp=JSON.parse('{"title":"配置","description":"","frontmatter":{},"headers":[],"relativePath":"guide/config/index.md","filePath":"guide/config/index.md","lastUpdated":1772677403000}'),bp={name:"guide/config/index.md"};function Ep(Np,t,Dp,Ip,Lp,up){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h1><h2 id="vlan" tabindex="-1">VLAN <a class="header-anchor" href="#vlan" aria-label="Permalink to &quot;VLAN&quot;">​</a></h2><h3 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h3><p>VLAN 是虚拟局域网（Virtual Local Area Network）的简称，它是在一个物理网络上划分出来的逻辑网络。这个网络对应于ISO模型的第二层网络。VLAN的划分不受网络端口的实际物理位置的限制。VLAN 有着和普通物理网络同样的属性，除了没有物理位置的限制，它和普通局域网一样。第二层的单播、广播和多播帧在一个VLAN内转发、扩散，而不会直接进入其它的VLAN之中。</p><p>基于端口的VLAN是最简单的一种VLAN划分方法。用户可以将设备上的端口划分到不同的VLAN中，此后从某个端口接收的报文将只能在相应的VLAN内进行传输，从而实现广播域的隔离和虚拟工作组的划分。</p><p>3.1.1.1 链接类型</p><p>根据端口在转发报文时对VLAN Tag的不同处理方式，可将端口的链路连接类型分为两种：</p><p>Access ：</p><p>端口发出去的报文不带VLAN Tag，一般用于和不能识别VLAN Tag的终端设备相连，或者不需要区分不同VLAN成员时使用。</p><p>Trunk ：</p><p>端口发出去的报文，端口缺省VLAN内的报文不带Tag，其它VLAN内的报文都必须带Tag。通常用于网络传输设备之间的互连。</p><p>Hybrid ：</p><p>端口发出去的报文可根据需要设置某些VLAN内的报文带Tag，某些VLAN内的报文不带Tag。Hybrid 类型端口既可以用于网络传输设备之间的互连，又可以直接连接终端设备。</p><p>3.1.1.2 缺省VLAN（PVID）</p><p>除了可以设置端口允许通过的VLAN，还可以设置端口的缺省VLAN。在缺省情况下，所有端口的缺省VLAN均为VLAN 1，但用户可以根据需要进行配置。</p><p>• Access端口的缺省VLAN就是它所属的VLAN。</p><p>• Trunk 端口和 Hybrid端口可以允许多个VLAN 通过，能够配置缺省VLAN。</p><p>• 当删除某个VLAN时，如果该VLAN是某个端口的缺省VLAN，则对Access端口，端口的缺省VLAN 会恢复到VLAN 1；对Trunk或Hybrid端口，端口的缺省VLAN配置不会改变，即它们可以使用已经不存在的VLAN作为缺省VLAN。</p><p>• 建议本端设备端口的缺省VLAN和相连的对端设备端口的缺省VLAN保持一致。</p><p>• 建议保证端口的缺省VLAN为端口允许通过的VLAN。如果端口不允许某VLAN通过，但是端口的缺省VLAN</p><p>为该VLAN，则端口会丢弃收到的该VLAN的报文或者不带 VLAN Tag 的报文。</p><p>• Web网管不支持配置Hybrid口，如需此功能请使用CLI配置方式。</p><p>3.1.1.3 端口对报文的处理方式</p><p>在配置了端口连接类型和缺省VLAN后，端口对报文的接收和发送的处理有几种不同情况，具体情况如表3-1所示。</p><p><strong>表3-1 端口收发报文的处理</strong></p><table tabindex="0"><thead><tr><th>端口类型</th><th>对接收报文的处理</th><th>对接收报文的处理</th><th>对发送报文的处理</th></tr></thead><tbody><tr><td>端口类型</td><td>接收的报文不带Tag 时</td><td>接收的报文带有 Tag 时</td><td>对发送报文的处理</td></tr><tr><td>Access</td><td>为报文添加缺省VLAN的 Tag</td><td>当VLAN与缺省VLAN相同时，接收该报文 当VLAN与缺省VLAN不同时，丢弃该报文</td><td>去掉Tag，发送该报文</td></tr><tr><td>Trunk</td><td>当缺省VLAN在端口允许通过的VLAN列 表中时，接收该报文，为报文添加缺省VLAN 的 Tag 当缺省VLAN不在端口允许通过的VLAN列表中时，丢弃该报文</td><td>当VLAN在端口允许通过的VLAN列表中时，接收该报文 当VLAN不在端口允许通过的VLAN列表中时，丢弃该报文</td><td>当VLAN与缺省VLAN相同，且在端口允许通过的VLAN列表中时，去掉Tag，发送该报文 当VLAN与缺省VLAN不同，且在端口允许通过的VLAN列表中时，保持原有Tag，发送该报文</td></tr><tr><td>Hybrid</td><td>当缺省VLAN在端口允许通过的VLAN列 表中时，接收该报文，为报文添加缺省VLAN 的 Tag 当缺省VLAN不在端口允许通过的VLAN列表中时，丢弃该报文</td><td>当VLAN在端口允许通过的VLAN列表中时，接收该报文 当VLAN不在端口允许通过的VLAN列表中时，丢弃该报文</td><td>当VLAN在端口允许通过的VLAN列表中时，发送该报文，是否去掉Tag可由用户手动配置</td></tr></tbody></table><h3 id="配置vlan" tabindex="-1">配置VLAN <a class="header-anchor" href="#配置vlan" aria-label="Permalink to &quot;配置VLAN&quot;">​</a></h3><p>3.1.2.1 VLAN配置简介</p><p>配置基于Access端口的VLAN</p><p><strong>表3-2 基于Access端口的VLAN配置步骤</strong></p><table tabindex="0"><thead><tr><th>步骤</th><th>配置任务</th><th>说明</th></tr></thead><tbody><tr><td>1</td><td>配置端口的连接类型</td><td>可选 配置端口的连接类型为Access ，缺省情况下，端口的连接类型为Access</td></tr><tr><td>2</td><td>创建VLAN</td><td>必选创建一个或多个VLAN</td></tr><tr><td>3</td><td>配置端口的缺省VLAN</td><td>配置Access端口的缺省VLAN</td></tr></tbody></table><p>配置基于Trunk端口的VLAN</p><p><strong>表3-3 基于Trunk端口的VLAN配置步骤</strong></p><table tabindex="0"><thead><tr><th>步骤</th><th>配置任务</th><th>说明</th><th>说明</th></tr></thead><tbody><tr><td>1</td><td>配置端口的连接类型</td><td>必选 配置端口的连接类型为Trunk 缺省情况下，端口的连接类型为Access</td><td>缺省情况下，Trunk端口的 Untagged VLAN（即缺省 VLAN）为VLAN 1 改变 Trunk 端口的 Untagged VLAN（即其缺省 VLAN）时，该端口原来的 Untagged VLAN将自动变为其 Tagged VLAN</td></tr><tr><td>2</td><td>创建需要添加到该Trunk口中的VLAN</td><td>必选创建一个或多个VLAN</td><td>必选创建一个或多个VLAN</td></tr><tr><td>3</td><td>配置VLAN所属的Trunk</td><td>选择对应的Trunk口，将VLAN添加</td><td>必选 Trunk端口只有一个Untagged VLAN，即其缺省VLAN。</td></tr></tbody></table><p>3.1.2.2 配置VLAN中的端口</p><p>VLAN配置界面如图3-1所示，各参数详细说明如表3-4所示。</p><p><img src="'+a+'" alt="VLAN配置界面"></p><p align="center"><em>图3-1 VLAN配置界面</em></p><p><strong>表3-4 VLAN配置相关参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>ID</td><td>VLAN序号</td></tr><tr><td>名称</td><td>VLAN名称，不支持配置，默认VLAN 1为default，VLAN 2为VLAN0002。</td></tr><tr><td>类型</td><td>Static\\Dynamic，当前版本仅支持Static</td></tr><tr><td>Tagged成员端口</td><td>端口Tagged成员列表</td></tr><tr><td>Untagged成员端口</td><td>端口Untagged成员列表</td></tr><tr><td>编辑</td><td>选择需要编辑的VLAN ID，点击此按钮进入编辑界面。</td></tr><tr><td>添加</td><td>点击此按钮进入VLAN添加界面。</td></tr><tr><td>删除</td><td>选择需要编辑的VLAN ID，点击此按钮删除该VLAN。</td></tr></tbody></table><p>配置步骤：</p><p>（1）在导航栏中选择【配置】【VLAN】，进入VLAN配置界面，如图3-2所示。</p><p>（2）单击【添加】按钮，进入如图3-1-2-2所示的页面。</p><p>（3）在ID框里，输入需要创建的VLAN。</p><p>（4）输入VLAN名称，单击【确认】按钮完成操作。</p><p>（5）单击辅助区的【保存】按钮，保存配置。</p><p>（6）当需要配置VLAN端口成员时，可单击【编辑】按钮，在端口面板中选取需要加入该VLAN的端口成员，单击【确认】按钮完成操作。</p><p>（7）当多个VLAN需要被同时创建时，可以用“n-m”的方式，如“2-10”。当单次创建的VLAN数量大于100时，请使用CLI命令行进行配置。</p><p><img src="'+i+'" alt="创建VLAN"></p><p align="center"><em>图3-2 创建VLAN</em></p><p>3.1.2.3 端口配置</p><p>端口配置界面如图3-3所示，各参数详细说明如表3-5所示。</p><p><img src="'+n+'" alt="端口配置界面"></p><p align="center"><em>图3-3 端口配置界面</em></p><p><strong>表3-5 接口配置相关参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>模式</td><td>Access</td><td>配置端口类型为Access口</td></tr><tr><td>模式</td><td>Trunk</td><td>配置端口类型为Trunk口</td></tr><tr><td>PVID/Native VLAN</td><td>PVID/Native VLAN</td><td>配置Access口的PORT-BASE VLAN ID或者Trunk口的Native VLAN</td></tr><tr><td>Allow VLANs</td><td>Allow VLANs</td><td>选择端口VLAN，适用于Trunk口</td></tr></tbody></table><p>配置步骤：</p><p>（1）在导航栏中选择【配置】【VLAN】，进入接口配置界面，如图3-4所示。</p><p>（2）点击Trunk口配置下方的【批量编辑】按钮，进入接口配置页面。</p><p>（3）配置端口的VLAN模式，以及PVID或者Native Vlan，一般情况下，建议Trunk口的Native VLAN配置为“1”，Allow VLANs为“all”，配置界面如图3-4所示，单击【确认】按钮完成配置。</p><p><img src="'+o+'" alt="VLAN配置界面"></p><p align="center"><em>图3-4 VLAN配置界面</em></p><p>（4）单击辅助栏的【保存】按钮，保存配置。</p><h3 id="vlan配置举例" tabindex="-1">VLAN配置举例 <a class="header-anchor" href="#vlan配置举例" aria-label="Permalink to &quot;VLAN配置举例&quot;">​</a></h3><p>配置范例：</p><p>案例需求:Switch A与Switch B通过trunk口互连，相同VLAN的PC之间可以互访，不同VLAN的PC之间禁止互访，网络拓扑如图3-5所示；</p><p><img src="'+s+'" alt="网络拓扑图"></p><p align="center"><em>图3-5 网络拓扑图</em></p><p>Switch A配置：</p><p>步骤1：配置GigabitEthernet 0/1为access口，PVID为10，GigabitEthernet 0/2为access口，PVID为20。</p><p>在导航栏【配置】选择【VLAN】，进入VLAN配置界面。点击【添加】按钮，在弹出的对话框里，ID框里输入“10”，点击选中端口GigabitEthernet 0/1，点击【确认】按钮，完成配置，如图3-6所示。</p><p><img src="'+g+'" alt="VLAN配置界面"></p><p align="center"><em>图3-6 VLAN配置界面</em></p><p>使用同样的步骤完成对端口GigabitEthernet 0/2的配置，如图3-7所示。</p><p><img src="'+m+'" alt="SWITCH B VLAN配置界面"></p><p align="center"><em>图3-7 SWITCH B VLAN配置界面</em></p><p>配置完成后的VLAN界面如图3-8所示。</p><p><img src="'+c+'" alt="SWITCH B VLAN配置界面"></p><p align="center"><em>图3-8 SWITCH B VLAN配置界面</em></p><p>步骤2：创建Trunk口GigabitEthernet 0/9</p><p>在当前界面，点击Trunk口下方的【批量编辑】按钮，如图3-9所示，依次选择“Trunk”，Native VLAN“1”，Allow VLANs“all”，端口面板单击选择GigabitEthernet 0/9，点击【确定】按钮完成配置。</p><p><img src="'+l+'" alt="添加VLAN界面"></p><p align="center"><em>图3-9 添加VLAN界面</em></p><p>配置成功的Trunk口GigibitEthernet0/9如图3-10所示。</p><p><img src="'+h+'" alt="Trunk口配置界面"></p><p align="center"><em>图3-10 Trunk口配置界面</em></p><p>配置完成后的VLAN 列表如图3-11所示。</p><p><img src="'+A+'" alt="VLAN界面"></p><p align="center"><em>图3-11 VLAN界面</em></p><p>步骤5：点击辅助区的【保存】按钮，保存配置。</p><p>Switch B配置：</p><p>配置方法同Switch A，把GigabitEthernet 0/9配置为trunk口。创建VLAN 10和VLAN 20并完成对应的端口配置。配置完成后，VLAN界面如图3-12所示。</p><p><img src="'+P+'" alt="Switch B VLAN界面"></p><p align="center"><em>图3-12 Switch B VLAN界面</em></p><h2 id="端口" tabindex="-1">端口 <a class="header-anchor" href="#端口" aria-label="Permalink to &quot;端口&quot;">​</a></h2><h3 id="端口配置" tabindex="-1">端口配置 <a class="header-anchor" href="#端口配置" aria-label="Permalink to &quot;端口配置&quot;">​</a></h3><p>由于电口和光口的部分参数不同，选择多端口配置时，建议对电口和光口分开进行配置。</p><p>端口管理模块用于配置以太网接口的工作参数，包括：描述、端口模式、介质类型、速率、双工状态、流控、MTU、状态，如图3-13所示。</p><p><img src="'+S+'" alt="端口管理界面"></p><p align="center"><em>图3-13 端口管理界面</em></p><p>操作步骤:</p><p>（1）在导航栏中选择【配置】【端口】【端口配置】，如图3-13所示。</p><p>（2）单击【编辑】或【批量编辑】按钮，进入如图3-14所示的页面。</p><p>（3）配置端口的工作参数，具体参数说明如表3-6所示。</p><p>（4）单击【确定】按钮完成操作。</p><p>（5）单击导航栏的【保存】按钮保存配置。</p><p><strong>表3-6 接口工作参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>描述</td><td>设置端口的描述信息，可以使用字母和数字组合。</td></tr><tr><td>介质类型</td><td>配置复用端口的介质类型，仅对支持光电复用(Combo)的端口有效。 RJ45：设置端口工作在电口模式。 SFP：设置端口工作在光口模式。 这里是否需要加上光点自适应的？</td></tr><tr><td>速率</td><td>设置端口的速率 10M：10Mbps 100M：100Mbps 1000M：1000Mbps AUTO：自动协商端口速率</td></tr><tr><td>双工状态</td><td>设置端口的双工状态 AUTO：自协商双工状态 FULL：全双工状态 HALF：半双工状态</td></tr><tr><td>端口模式 （仅适用于光口）</td><td>设置端口的工作模式以支持不同的工作模式，不同的模式需要相应的光模块支持。 100BASE-FX：设置端口工作在百兆光模式。 1000BASE-X：设置端口工作在千兆光模式。 SGMII：设置端口工作在SGMII模式，当光口插入的模块为千兆转百兆光（SFP GE-FX）或者是光转电模块（Mini-GBIC-GT）时，需要配置为此模式。 2500BASE-X：设置端口工作在2.5G光口模式。 10G BASE-X:设置端口工作在10G光口模式。 2500BASE-X模式，与其他厂家的端口互联可能存在不兼容的情况。 不同型号的设备的光口能力是不一样的，具体请参考具体产品型号对应的说明文档。</td></tr><tr><td>自协商 （仅适用于光口）</td><td>开启/关闭光口的自协商功能。 OFF：光口关闭自协商，工作在强制状态。 ON：光口开启自协商。</td></tr><tr><td>流控</td><td>设置使能（Enable）或禁止（Disable）端口流量控制功能 当本端和对端设备都使能了流量控制功能后，如果本端设备发生拥塞，就向对端设备发送消息，通知对端设备暂时停止发送报文；对端设备在接收到该消息后将暂时停止向本端发送报文；反之亦然。从而避免了报文丢失现象的发生 只有本端和对端端口都开启了流量控制功能，才能实现流量控制</td></tr><tr><td>MTU</td><td>设置允许转发的帧长，支持的帧长范围46-10222 bytes，默认为1500 bytes。</td></tr><tr><td>管理状态</td><td>设置端口的打开/关闭状态。 No shutdown：设置端口工作在正常工作状态。 Shutdown：设置端口工作在关闭状态。</td></tr></tbody></table><p><img src="'+_+'" alt="接口配置界面"></p><p align="center"><em>图3-14 接口配置界面</em></p><p>配置举例:</p><p>案例需求：配置端口GigabitEthernet0/9为2.5G工作模式，关闭流控，MTU设置为10000 bytes，端口描述为abc。</p><p>步骤1：在导航栏中选择【接口】【端口管理】,进入端口管理界面。</p><p>步骤2：选择端口GigabitEthernet0/9，点击【编辑】按钮进入端口配置界面，如图3-15所示。</p><div class="tip custom-block"><p class="custom-block-title">步骤3: 按照图3-2-3所示，按照描述“abc”，介质类型“SFP”，端口模式“2500BASE-X”，流控“OFF”，MTU“10000”，管理状态“No shutdown”，配置好参数。</p></div><p>步骤4：单击【确认】按钮完成操作。</p><p>步骤5：单击辅助栏的【保存】按钮保存配置。</p><p><img src="'+b+'" alt="接口配置举例"></p><p align="center"><em>图3-15 接口配置举例</em></p><h3 id="端口扩展" tabindex="-1">端口扩展 <a class="header-anchor" href="#端口扩展" aria-label="Permalink to &quot;端口扩展&quot;">​</a></h3><p>3.2.2.1 端口限速</p><p>端口限速就是基于端口的速率限制，它对端口输入、输出报文的总速率进行限制。在流量从接口发出前，在接口的出方向上配置限速，对流出的所有报文流量进行控制。在流量从接口接收前，在接口的入口方向上配置限速，对流入的所有报文流量进行控制。</p><p>操作步骤:</p><p>（1）在导航栏中选择【配置】【端口】【端口扩展】,进入端口限速配置界面，如图3-16所示。</p><p>（2）对需要配置限速的端口，在对话框中输入相应数值，具体参数定义如表3-7所示。</p><p>（3）单击对应端口的【应用】按钮完成操作。</p><p>（4）单击导航栏的【保存】按钮保存配置。</p><p><img src="'+E+'" alt="端口限速界面"></p><p align="center"><em>图3-16 端口限速界面</em></p><p>limit数值是可确定的，比如限速1M，那么limit数值为1024，但是burst的数值却取自经验数值。当burst</p><p>数值配大，流量尖峰更高，限速较稳定，但平均速率可能高于限速值；当burst数值配小，流量尖峰较低，限速</p><p>波动较大，平均速率可能小于限速值。建议burst配置取limit的4倍值与16384的小值。</p><p><strong>表3-7 参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td>端口名称</td></tr><tr><td>输入速率（kbps）</td><td>输入方向的每秒钟的带宽限制量(KBits)</td></tr><tr><td>输入突发流量（KB）</td><td>输入方向的突发流量限制值(Kbytes)</td></tr><tr><td>输出速率（kbps）</td><td>输出方向的每秒钟的带宽限制量(KBits)</td></tr><tr><td>输出突发流量（KB）</td><td>输出方向的突发流量限制值(Kbytes)</td></tr><tr><td>操作</td><td>编辑或者删除此条例</td></tr></tbody></table><p>配置举例:</p><p>案例需求：假设交换机的端口GigabitEthernet0/1连到Internet，需要在端口GigabitEthernet0/1出口流量限制，带宽限制每秒 102400KBits，突发流量限制每秒256Kbytes。</p><p>步骤1：在导航栏中选择【配置】【端口】【端口扩展】，进入端口限速配置界面。</p><p>步骤2：点击关闭输入限速按钮，在输出限速对话框里输入对应的数值，面板图上点击选择端口1，如图3-17所示。</p><p>步骤3：点击【确定】按钮，完成配置。</p><p><img src="'+N+'" alt="图3-17端口限速配置界面"></p><p align="center"><em>图3-17端口限速配置界面</em></p><p>步骤4：单击辅助区的【保存】按钮保存配置。</p><p>3.2.2.2 风暴抑制</p><p>当局域网中存在过量的广播、多播或未知单播数据流时，将导致网络性能下降，甚至网络瘫痪的现象，称为广播风暴。风暴控制针对广播、多播和未知单播数据流进行限速，当交换机端口接收到的广播、未知名多播或未知单播数据流的速率超过所设定的带宽时，设备将只允许通过所设定带宽的数据流，超出带宽部分的数据流将被丢弃，从而避免过量的泛洪数据流进入 LAN 中形成风暴。</p><p>风暴控制模块，用于设置端口对于广播、组播、未知名单播报文的抑制比。采用的是基于带宽百分比的风暴控制模式。当设备端口接收到的数据流的速率超过所设定的带宽时，设备将只允许通过所设定带宽的数据流，超出带宽部分的数据流将被丢弃，直到数据流恢复正常。</p><p>配置步骤:</p><p>（1）在导航栏中选择【配置】【端口】【端口扩展】，进入风暴控制界面，如图3-18所示。</p><p><img src="'+D+'" alt="风暴控制状态界面"></p><p align="center"><em>图3-18 风暴控制状态界面</em></p><p>（2）点击“风暴控制”下方的【批量编辑】按钮，进入如图3-19所示的页面。</p><p>（3）配置端口的风暴抑制类型及带宽抑制比，详细配置如表3-8所示，在端口面板上选择需要配置的端口。</p><p>（4）单击【确认】按钮完成操作。</p><p>（5）单击导航栏的【保存】按钮保存配置。</p><p><img src="'+I+'" alt="端口配置界面"></p><p align="center"><em>图3-19 端口配置界面</em></p><p><strong>表3-8 参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td>名称</td><td>选中的端口</td></tr><tr><td>类型</td><td>disabled</td><td>关闭此功能。</td></tr><tr><td>类型</td><td>broadcast</td><td>开启广播报文风暴抑制功能，可以实现对广播报文的流量限制。</td></tr><tr><td>类型</td><td>multicast</td><td>开启未知名组播报文风暴抑制功能，可以实现对未知名组播报文的流量限制。</td></tr><tr><td>类型</td><td>unicast</td><td>开启未知名单播报文风暴抑制功能，可以实现对未知名单播报文的流量限制。</td></tr><tr><td>类型</td><td>multicast – broadcast</td><td>开启组播报文+广播报文风暴抑制功能，可以实现对未知名组播报文和广播报文的流量限制。</td></tr><tr><td>类型</td><td>unicast-broadcast</td><td>开启未知名单播报文+广播报文风暴抑制功能，可以实现对未知名单播报文和广播报文的流量限制。</td></tr><tr><td>类型</td><td>all</td><td>选择抑制广播、多播、未知名单播</td></tr><tr><td>带宽比率（%）</td><td>带宽比率（%）</td><td>允许通过的最大广播流量占该端口传输能力的百分比，选择此项后需输入具体的百分数</td></tr></tbody></table><p>配置举例:</p><p>案例需求：开启端口GigabitEthernet0/1的风暴控制，对广播报文的抑制比设置为10%。</p><p>步骤1：在导航栏中选择【配置】【端口】【端口扩展】,进入风暴控制界面。</p><p>步骤2：点击【批量配置】按钮，进入配置界面。</p><p>步骤3：类型选择broadcast，带宽比率设置为10，如图3-20所示，端口面板选择Gigabitethernet0/1。</p><p>步骤4：单击【确定】按钮完成操作。</p><p><img src="'+L+'" alt="风暴控制配置界面"></p><p align="center"><em>图3-20 风暴控制配置界面</em></p><p>步骤5：单击辅助区的【保存】按钮保存配置。</p><p>3.2.2.3 端口隔离</p><p>为了实现报文之间的二层隔离，可以将不同的端口加入不同的 VLAN，但会浪费有限的VLAN资源。采用端口隔离特性，可以实现同一VLAN内端口之间的隔离。用户只需要将端口加入到隔离组中，就可以实现隔离组内端口之间二层数据的隔离。端口隔离功能为用户提供了更安全、更灵活的组网方案。端口隔离特性与端口所属的VLAN无关。不支持上行端口的设备，隔离组内的端口和隔离组外端口二层流量双向互通。</p><p>配置步骤:</p><p>（1）在导航栏中选择【配置】【端口】【端口扩展】，进入端口隔离界面，如图3-21所示。</p><p>（2）点击“端口隔离”下方的【批量编辑】按钮，进入端口隔离配置界面，点击【确认】按钮完成配置。</p><p>（3）单击辅助区【保存】按钮，保存配置。</p><p><img src="'+u+'" alt="端口隔离界面"></p><p align="center"><em>图3-21 端口隔离界面</em></p><p>配置举例：</p><p>组网需求，如图3-22所示：</p><p>• 小区用户User1、 User2、 User3分别与 Switch 的端口GigabitEthernet 0/2、GigabitEthernet 0/3、GigabitEthernet 0/4相连。</p><p>• 设备通过 gigabitGigabitEthernet 0/1端口与外部网络相连。</p><p>• GigabitEthernet0/1、GigabitEthernet 0/2、GigabitEthernet 0/3、GigabitEthernet 0/4属于同一 VLAN；实现小区用户 User1、 User2和User3彼此之间二层报文不能互通，但可以和外部网络通信。</p><p><img src="'+R+'" alt="组网拓扑"></p><p align="center"><em>图3-22 组网拓扑</em></p><p>步骤1：在导航栏中选择【配置】【端口】【端口扩展】，进入端口隔离界面。</p><p>步骤2：在端口面板选择GigabitEthernet 0/2、GigabitEthernet 0/3、GigabitEthernet 0/4，如图3-23所示，点击【OK】按钮完成配置。</p><p><img src="'+V+'" alt="端口隔离配置界面"></p><p align="center"><em>图3-23 端口隔离配置界面</em></p><div class="tip custom-block"><p class="custom-block-title">步骤3:点击导航栏的【保存】按钮，保存配置。</p></div><h3 id="端口镜像" tabindex="-1">端口镜像 <a class="header-anchor" href="#端口镜像" aria-label="Permalink to &quot;端口镜像&quot;">​</a></h3><p>SPAN（Local Switched Port Analyzer）为本地镜像功能。SPAN功能将指定端口的报文复制到目的端口，一般SPAN目的端口会接入数据检测设，用户利用这些设备分析目的端口接收到的报文，进行网络监控和故障排除，SPAN的源端口与目的端口，在同一台设备上，如图3-24所示。</p><p><img src="'+C+'" alt="端口镜像"></p><p align="center"><em>图3-24 端口镜像</em></p><p>RSPAN（Remote Switch Port Analyzer，远程端口镜像）是SPAN的扩展。远程镜像源端口和目的端口之间可以跨越多个网络设备。远程镜像的原理是原设备、中间设备和目的设备通过创建一个Remote VLAN，且所有参与会话的端口都要加入该Remote VLAN中，镜像报文在Remote VLAN 内进行广播，使得镜像报文从源设备的源端口传送到目的设备的目的端口，如图3-25所示。</p><p><img src="'+M+'" alt="远程端口镜像"></p><p align="center"><em>图3-25 远程端口镜像</em></p><p>SPAN/RSPAN 并不影响源端口的报文交换，只是将源端口所有进入和输出的报文原样复制了一份到目的端口。当源端口的镜像流量超过目的端口带宽的情况下，例如100Mbps 目的端口监控 1000Mbps 源端口的流量，可能导致报文被丢弃。</p><p>SPAN/RSPAN基于会话管理，在会话中配置SPAN的源端口与目的端口。在一个会话中，只能有一个目的端口，但是可以同时配置多个源端口。</p><p>配置步骤：</p><p>（1）在导航栏中选择【配置】【端口】【端口镜像】，进入如图3-26所示的页面。</p><p><img src="'+U+'" alt="端口镜像界面"></p><p align="center"><em>图3-26 端口镜像界面</em></p><p>（2）点击表格上方的【添加】按钮，进入端口镜像配置界面，如图3-27所示，具体参数如表3-9所描述。</p><p><img src="'+T+'" alt="图3-27端口镜像配置界面"></p><p align="center"><em>图3-27端口镜像配置界面</em></p><p>（3）根据要求填写好参数，点击【确认】按钮完成配置。</p><p><strong>表3-9 参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>会话</td><td>选择要进行配置的端口镜像组的组号，一共可以创建7个镜像组。</td></tr><tr><td>描述</td><td>配置创建的镜像组描述符</td></tr><tr><td>模式</td><td>配置镜像组的模式，默认为本地镜像，Source是远程镜像的源设备，Destination是远程镜像的目的设备</td></tr><tr><td>源接收接口</td><td>选择镜像源接收端口，允许有多个源接收端口同时存在</td></tr><tr><td>源发送接口</td><td>选择镜像源发送端口，允许有多个源发送端口同时存在</td></tr><tr><td>源VLAN</td><td>创建/删除SPAN源VLAN，VLAN支持range模式，源VLAN只能支持一个会话，源VLAN和源端口不能共存</td></tr><tr><td>目标接口</td><td>选择镜像目的端口，每个会话只允许有一个目的端口</td></tr><tr><td>交换</td><td>SPAN的目的口是否参与交换</td></tr><tr><td>远程VLAN</td><td>创建/删除RSPAN源VLAN，VLAN支持range模式，源VLAN只能支持一个会话，源VLAN和源端口不能共存</td></tr></tbody></table><p>配置举例:</p><p>案例需求：利用远端设备SWITCH-C的端口gigabitEthernet0/8，监控本地设备SWITCH-A的端口gigabitEthernet0/1的rx报文，Remote-vlan为1000， 中间设备支持VLAN1000的报文广播，监控会话名称设定为“TRAFFIC_MONITOR_REMOTE”。组网如图3-28所示：</p><p><img src="'+y+'" alt="组网拓扑"></p><p align="center"><em>图3-28 组网拓扑</em></p><p>Switch A配置：</p><p>步骤1：在导航栏中选择【配置】【端口】【端口镜像】，进入端口镜像配置界面。</p><p>步骤2：点击对应会话1的【编辑】按钮，按照图3-29所示，会话上配置描述信息为“TRAFFIC_MONITOR_SOURCE”，模式为Remote-source，源端口为GigabitEthernet 0/1，目的端口为GigabitEthernet 0/8，远程VLAN为1000。</p><p>步骤3：单击辅助区的【保存】按钮保存配置。</p><p><img src="'+w+'" alt="Switch A端口镜像配置界面"></p><p align="center"><em>图3-29 Switch A端口镜像配置界面</em></p><p>Switch B配置：</p><p>步骤1：在导航栏中选择【配置】【VLAN】，进入VLAN配置界面。</p><p>步骤2：点击“VLAN配置”的【添加】按钮，创建VLAN 1000。</p><p>步骤3：点击表格中的【编辑】按钮，按照图3-30所示，配置GigabitEthernet 0/1和GigabitEthernet 0/2为Trunk口，Trunk口VLAN为1000。</p><p>步骤4：单击辅助区的【保存】按钮保存配置。</p><p><img src="'+k+'" alt="Switch B VLAN配置界面"></p><p align="center"><em>图3-30 Switch B VLAN配置界面</em></p><p>Switch C配置：</p><p>步骤1：在导航栏中选择【配置】【VLAN】，进入VLAN配置界面。</p><p>步骤2：点击“VLAN配置”的【添加】按钮，创建VLAN 1000。</p><p>步骤3：按照图3-31所示，配置GigabitEthernet 0/8为Access口，端口VLAN为1000。</p><p><img src="'+f+'" alt="Switch C VLAN配置界面"></p><p align="center"><em>图3-31 Switch C VLAN配置界面</em></p><p>步骤4：在导航栏中选择【配置】【端口】【端口镜像】，进入端口镜像配置界面。</p><p>步骤5：点击对应会话1的【编辑】按钮，按照图3-32所示，会话上配置描述信息为“TRAFFIC_MONITOR_DESTINATION”，模式为Remote-destination，目的端口为GigabitEthernet 0/8，远程VLAN为1000。</p><p>步骤6：单击辅助区的【保存】按钮保存配置。</p><p><img src="'+q+'" alt="Switch C端口镜像配置界面"></p><p align="center"><em>图3-32 Switch C端口镜像配置界面</em></p><h3 id="端口聚合" tabindex="-1">端口聚合 <a class="header-anchor" href="#端口聚合" aria-label="Permalink to &quot;端口聚合&quot;">​</a></h3><p>3.2.4.1 概述</p><p>聚合口</p><p>将多个物理链接捆绑在一起建立一个逻辑链接，这个逻辑链接我们称之为聚合口( port-channel，以下简称 PO口）。该功能符合IEEE802.3ad标准，它可以用于扩展链路带宽，提供更高的连接可靠性，常用于端口上联，如图3-33所示。</p><p><img src="'+x+'" alt="端口聚合组网模型"></p><p align="center"><em>图3-33 端口聚合组网模型</em></p><p>聚合口具备以下几个特性：</p><p>（1）高带宽，聚合口总带宽为物理成员口带宽总和；</p><p>（2）支持流量均衡策略，可以根据策略把流量地分配给各成员链路；</p><p>（3）支持链路备份，当聚合口中的一条成员链路断开时，系统会将该成员链路的流量自动地分配到聚合口中的其它有效成员链路上。</p><p>LACP</p><p>基于IEEE802.3ad标准的LACP（Link Aggregation Control Protocol，链路汇聚控制协议）是一种实现链路动态汇聚的协议。如果端口启用LACP 协议，端口会发送LACPDU来通告自己的系统优先级、系统MAC、端口的优先级、端口号和操作key 等。相连设备收到对端的LACP 报文后，根据报文中的系统ID 比较两端的系统优先级。在系统ID 优先级较高的一端，将按照端口ID 优先级从高到低的顺序，设置聚合组内端口处于聚合状态，并发出更新后的LACP报文，对端设备收到报文后，也会把相应的端口设置成聚合状态，从而使双方在端口退出或者加入聚合口上达到一致。只有双方的端口都完成动态聚合绑定操作后，该物理链路才能进行数据报文的转发。</p><p>LACP 成员口链路绑定之后，还会进行周期性的LACP 报文交互，在一段时间没有收到LACP 报文时，就认为收包超时，成员口链路解除绑定，端口重新处于不可转发状态。这里的超时时间有两种模式:长超时模式和短超时模式。在长超时模式下，端口间隔30 秒发送一个报文，若90秒没有收到对端报文，就处于收包超时；在短超时模式下，端口间隔1 秒发送一个报文，若3秒钟没有收到对端报文，就处于收包超时。</p><p><img src="'+G+'" alt="端口聚合模型"></p><p align="center"><em>图3-34 端口聚合模型</em></p><p>如图3-34所示，交换机A和交换机B通过3个端口连接在一起。设置交换机A的系统优先级为61440，设置交换机B的系统优先级为4096。在交换机A和B的3个直连端口上打开LACP端口聚合，设置3个端口的聚合模式为主动模式，设置3个端口的端口优先级为默认优先级32768。</p><p>在收到对端的LACP 报文后，交换机B发现自己的系统ID 优先级比较高(交换机B 的系统优先级比交换机A 高)，于是按照端口ID 优先级的顺序(端口优先级相同的情况下，按照端口号从小到大的顺序)设置端口4、5、6 处于聚合状态。交换机A 收到交换机B 更新后的LACP 报文后，发现对端的系统ID优先级比较高，并且把端口设置成聚合状态了，也把端口1、2、3 设置成聚合状态了。</p><p>3.2.4.2 配置聚合端口</p><p>配置步骤：</p><p>(1)在导航栏中选择【配置】【端口】【端口聚合】，进入端口聚合配置界面，在全局配置界面选择负载均衡算法，如图3-35所示，参数说明如表3-10所示。</p><p><img src="'+v+'" alt="合配置界面"></p><p align="center"><em>图3-35 合配置界面</em></p><p><strong>表3-10全局配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th><th>说明</th></tr></thead><tbody><tr><td>全局配置</td><td>均衡算法</td><td>dst-mac</td><td>根据目的MAC地址进行均衡。</td></tr><tr><td>全局配置</td><td>均衡算法</td><td>src-mac</td><td>根据源MAC地址进行均衡。</td></tr><tr><td>全局配置</td><td>均衡算法</td><td>src-dst-mac</td><td>根据源MAC地址和目的MAC进行均衡。</td></tr><tr><td>全局配置</td><td>均衡算法</td><td>dst-ip</td><td>根据目的IP地址进行均衡。</td></tr><tr><td>全局配置</td><td>均衡算法</td><td>srt-ip</td><td>根据源IP地址进行均衡。</td></tr><tr><td>全局配置</td><td>均衡算法</td><td>src-dst-ip</td><td>根据源IP地址和目的IP地址进行均衡。</td></tr><tr><td>全局配置</td><td>均衡算法</td><td>dst-port</td><td>根据L4 TCP/UDP目的端口号进行均衡。</td></tr><tr><td>全局配置</td><td>均衡算法</td><td>src-port</td><td>根据L4 TCP/UDP源端口号进行均衡。</td></tr><tr><td>全局配置</td><td>均衡算法</td><td>src-dst-port</td><td>根据L4 TCP/UDP源端口号和目的端口号进行均衡。</td></tr></tbody></table><p>(2) 点击“聚合口”下方的【添加】按钮，配置“类型”，“ID”,点击选择端口面板的端口序号，如图3-36所示，参数说明表3-10所示。</p><p><img src="'+X+'" alt="聚合口成员配置界面"></p><p align="center"><em>图3-36 聚合口成员配置界面</em></p><p><strong>表3-11聚合成员口配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th><th>说明</th></tr></thead><tbody><tr><td>端口配置</td><td>ID</td><td>聚合口成员的ID</td><td>聚合口成员的ID</td></tr><tr><td>端口配置</td><td>类型</td><td>Manual</td><td>设置为手动模式</td></tr><tr><td>端口配置</td><td>类型</td><td>Active</td><td>该端口会主动发起LACP 聚合运算</td></tr><tr><td>端口配置</td><td>类型</td><td>Passive</td><td>该端口不会主动发起LACP 聚合运算，但是在接收到邻居的LACP 报文后会被动参与LACP 计算。</td></tr></tbody></table><p>点击【确定】完成配置，在聚合口界面会显示创建成功的聚合口ID和成员口信息，如图3-37所示，参数说明表3-12所示。</p><p><img src="'+O+'" alt="聚合口显示界面"></p><p align="center"><em>图3-37 聚合口显示界面</em></p><p><strong>表3-12 聚合口参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>聚合口</td><td>ID</td><td>聚合口的ID。</td></tr><tr><td>聚合口</td><td>名称</td><td>聚合口名称</td></tr><tr><td>聚合口</td><td>成员</td><td>具体的聚合口成员名称。</td></tr></tbody></table><p>3.2.4.3 配置举例</p><ol><li>组网需求</li></ol><p>• 如图3-38所示，Switch A与Switch B通过各自的二层以太网端口GigabitEthernet 0/1～GigabitEthernet /0/3相互连接。</p><p>• Switch A 和 Switch B 由三条物理链路连接。在 Switch A 和 Switch B 上把端口配置成端口聚合组，从而实现出/入负载在各成员端口中分担。</p><p><img src="'+B+'" alt="端口聚合举例"></p><p align="center"><em>图3-38 端口聚合举例</em></p><ol start="2"><li>配置步骤</li></ol><p>使用静态聚合口和动态聚合口均可以实现负载分担，下面将分别介绍这两种聚合口的配置方法，使用任何一种方法都可以实现需求。</p><p>方法一：配置静态聚合口</p><p>步骤 1：在导航栏中选择【配置】【端口】【端口聚合】，进入端口聚合配置界面。</p><p>步骤 2：在全局配置项中，选择“负载均衡算法”为src-ip，如图3-39所示。</p><p><img src="'+F+'" alt="图3-39全局配置"></p><p align="center"><em>图3-39全局配置</em></p><p>步骤 3：点击“聚合口”下方的【添加】按钮，端口面板选择GigabitEthernet 0/1、GigabitEthernet 0/2、GigabitEthernet 0/3， ID设置为“1”，模式选择“Manual”，如图3-40所示。</p><p><img src="'+H+'" alt="聚合成员口静态配置"></p><p align="center"><em>图3-40 聚合成员口静态配置</em></p><p>点击【确定】完成配置，在聚合口界面中，看到创建成功的聚合口po1，如图3-41所示。</p><p><img src="'+W+'" alt="创建成功的静态聚合口"></p><p align="center"><em>图3-41 创建成功的静态聚合口</em></p><p>步骤 4：点击辅助区的【保存】按钮，保存当前配置。</p><p>方法二：配置动态聚合组</p><p>步骤 1：在导航栏中选择【配置】【端口】【端口聚合】，进入端口聚合配置界面。</p><p>步骤 2：在全局配置项中，选择“负载均衡算法”为src-ip，如图3-42所示。</p><p><img src="'+K+'" alt="全局配置"></p><p align="center"><em>图3-42 全局配置</em></p><p>步骤 3：点击“聚合口”下方的【添加】按钮，端口面板选择GigabitEthernet 0/1、GigabitEthernet 0/2、GigabitEthernet 0/3， ID设置为“1”，模式选择“Active”，如图3-43所示。</p><p><img src="'+z+'" alt="聚合成员口动态配置"></p><p align="center"><em>图3-43 聚合成员口动态配置</em></p><p>点击【确定】完成配置，在聚合口界面中，看到创建成功的聚合口po1，如图3-44所示。</p><p><img src="'+$+'" alt="创建成功的动态聚合口"></p><p align="center"><em>图3-44 创建成功的动态聚合口</em></p><p>步骤 4：点击辅助区的【保存】按钮，保存当前配置。</p><h3 id="端口违例" tabindex="-1">端口违例 <a class="header-anchor" href="#端口违例" aria-label="Permalink to &quot;端口违例&quot;">​</a></h3><p>在设备使用过程中，交换机端口会发生主动或者被动的违例行为，比如端口安全的违例、端口震荡违例、端口环路检测违例等。端口违例模块用于配置违例端口的恢复使能及恢复时间，并显示端口的违例行为。</p><p>配置端口违例：</p><p>在导航栏中选择【配置】【端口】【端口违例】，进入端口违例全局配置界面，勾选需要违例的服务，打开自动恢复按钮并配置恢复时间，点击【应用】按钮完成配置，如图3-45所示，全局配置参数如表3-13所示。</p><p><img src="'+j+'" alt="端口违例全局配置"></p><p align="center"><em>图3-45 端口违例全局配置</em></p><p><strong>表3-13 端口违例参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>服务</td><td>BPDU Guard</td><td>端口BPDU保护引起的违例行为</td></tr><tr><td>服务</td><td>Port Up/Down</td><td>端口频繁Up/Down导致的违例行为</td></tr><tr><td>服务</td><td>Port Security</td><td>违法端口安全导致的违例行为</td></tr><tr><td>服务</td><td>Loop Detect</td><td>端口下联设备存在环路导致的违例行为</td></tr><tr><td>自动恢复</td><td>自动恢复</td><td>开启/关闭违例端口的自动恢复</td></tr><tr><td>恢复时间</td><td>恢复时间</td><td>配置违例端口的恢复时间，单位秒</td></tr></tbody></table><p>当需要手工恢复违例端口时，选择需要恢复的端口，点击【恢复】按钮，恢复端口功能。</p><p><img src="'+J+'" alt="端口违例状态"></p><p align="center"><em>图3-46 端口违例状态</em></p><h2 id="生成树" tabindex="-1">生成树 <a class="header-anchor" href="#生成树" aria-label="Permalink to &quot;生成树&quot;">​</a></h2><h3 id="概述-1" tabindex="-1">概述 <a class="header-anchor" href="#概述-1" aria-label="Permalink to &quot;概述&quot;">​</a></h3><p>生成树协议是一种二层管理协议，它通过选择性地阻塞网络中的冗余链路来消除二层环路，同时还具备链路备份的功能。</p><p>与众多协议的发展过程一样，生成树协议也是随着网络的发展而不断更新的，从最初的 STP（Spanning Tree Protocol，生成树协议）到 RSTP（Rapid Spanning Tree Protocol，快速生成树协议），再到最新的 MSTP（Multiple SpanningTree Protocol，多生成树协议）。</p><p>对二层以太网来说，两个 LAN 间只能有一条活动着的通路，否则就会产生广播风暴。但是为了加强一个局域网的可靠性，建立冗余链路又是必要的，其中的一些通路必须处于备份状态，如果当网络发生故障，另一条链路失效时，冗余链路就必须被提升为活动状态。手工控制这样的过程显然是一项非常艰苦的工作，STP 协议就自动地完成这项工作。它能使一个局域网中的设备起到以下作用：</p><p>• 发现并启动局域网的一个最佳的树型拓扑结构。</p><p>• 发现故障并随之进行恢复，自动更新网络拓扑结构，使在任何时候都选择了可能的最佳的树型结构。</p><h3 id="生成树配置" tabindex="-1">生成树配置 <a class="header-anchor" href="#生成树配置" aria-label="Permalink to &quot;生成树配置&quot;">​</a></h3><p>生成树模块提供了生成树的全局配置、MST配置、实例、接口等配置。</p><p>生成树全局配置</p><p>在导航栏中选择【配置】【生成树】【全局配置】，进入生成树全局配置界面，如图3-47所示。全局配置参数如表3-14所示。</p><p><img src="'+Q+'" alt="生成树全局配置"></p><p align="center"><em>图3-47 生成树全局配置</em></p><p><strong>表3-14 生成树概况参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>全局配置</td><td>模式</td><td>设置STP的工作模式，包括STP、 RSTP和MSTP STP：在 STP 模式下，设备的各个端口将向外发送 STP BPDU 报文 RSTP：在 RSTP 模式下，设备的各个端口将向外发送 RSTP BPDU报文，当发现与运行 STP 的设备相连时，该端口会自动迁移到 STP模式下工作 MSTP：在 MSTP 模式下，设备的各个端口将向外发送 MSTP BPDU报文，当发现与运行 STP 的设备相连时，该端口会自动迁移到 STP模式下工作</td></tr><tr><td>全局配置</td><td>状态</td><td>设置是否使能全局STP功能</td></tr><tr><td>全局配置</td><td>握手周期（秒）</td><td>设置设备为检测链路故障，发送hello报文的周期</td></tr><tr><td>全局配置</td><td>优先级</td><td>桥优先级</td></tr><tr><td>全局配置</td><td>转发延迟（秒）</td><td>设置设备状态迁移的延迟时间</td></tr><tr><td>全局配置</td><td>转发门限</td><td>桥每秒最多发送的BPDU报文数</td></tr><tr><td>全局配置</td><td>老化时间（秒）</td><td>设置消息在设备内保存的最大时长</td></tr><tr><td>全局配置</td><td>错误端口禁用超时</td><td>配置错误端口自动禁用功能</td></tr><tr><td>全局配置</td><td>错误端口禁用超时时间</td><td>配置错误端口自动禁用后超时解除禁用的时间</td></tr></tbody></table><p>生成树实例配置</p><p>在导航栏中选择【配置】【生成树】【实例配置】，进入生成树实例配置界面，如图3-48所示。实例配置参数如表3-15所示。</p><p><img src="'+Y+'" alt="生成树实例配置"></p><p align="center"><em>图3-48 生成树实例配置</em></p><p><strong>表3-15 生成树实例配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>实例</td><td>ID</td><td>实例ID</td></tr><tr><td>实例</td><td>VLAN列表</td><td>实例关联的所有VLAN，以列表形式显示</td></tr><tr><td>实例</td><td>优先级</td><td>当前实例中桥的优先级</td></tr><tr><td>实例</td><td>编辑</td><td>点击对改实例进行编辑</td></tr><tr><td>实例</td><td>删除</td><td>点击删除此实例</td></tr></tbody></table><p>生成树端口配置</p><p>在导航栏中选择【配置】【生成树】【端口配置】，进入生成树端口配置界面，如图3-49所示。端口配置参数如表3-16所示。</p><p><img src="'+Z+'" alt="生成树全局配置"></p><p align="center"><em>图3-49 生成树全局配置</em></p><p><strong>表3-16 生成树概况参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>端口配置</td><td>名称</td><td>接口名称</td></tr><tr><td>端口配置</td><td>状态</td><td>接口的生成树开关状态</td></tr><tr><td>端口配置</td><td>链路类型</td><td>配置接口链路类型</td></tr><tr><td>端口配置</td><td>根保护</td><td>配置接口开启根保护功能</td></tr><tr><td>端口配置</td><td>自动边缘端口</td><td>配置接口自动识别边缘端口的功能</td></tr><tr><td>端口配置</td><td>边缘端口</td><td>配置接口为边缘端口</td></tr><tr><td>端口配置</td><td>快速端口</td><td>配置接口为快速端口</td></tr><tr><td>端口配置</td><td>BDPU过滤</td><td>配置接口开启BPDU过滤</td></tr><tr><td>端口配置</td><td>BDPU保护</td><td>配置接口开启BPDU保护</td></tr><tr><td>端口配置</td><td>实例/优先级/TCN报文限制</td><td>配置实例ID、优先级、拓扑变化通告报文抑制功能</td></tr></tbody></table><h2 id="erps" tabindex="-1">ERPS <a class="header-anchor" href="#erps" aria-label="Permalink to &quot;ERPS&quot;">​</a></h2><h3 id="erps功能概述" tabindex="-1">ERPS功能概述 <a class="header-anchor" href="#erps功能概述" aria-label="Permalink to &quot;ERPS功能概述&quot;">​</a></h3><p>ERPS（GigabitEthernet ernet Ring Protection Switching，以太环网保护切换协议）为 ITU 开发的一种环网保护协议，也称G.8032。它是一个专门应用于以太环网的链路层协议。它在以太环网完整时能够防止数据环路引起的广播风暴，而当以太环网上一条链路断开时能迅速恢复环网上各个节点之间的通信。</p><p>目前，解决二层网络环路问题的技术还有 STP。STP 应用比较成熟，但其收敛的时间比较长（秒级）。ERPS 是专门应用于以太环网的链路层协议，二层收敛性能达50ms以内，具有比 STP 更快的收敛速度。</p><p><img src="'+tt+'" alt="ERPS典型组网"></p><p align="center"><em>图3-50 ERPS典型组网</em></p><h3 id="erps-原理简介" tabindex="-1">ERPS 原理简介 <a class="header-anchor" href="#erps-原理简介" aria-label="Permalink to &quot;ERPS 原理简介&quot;">​</a></h3><p>ERPS是一种专用于以太网链路层的标准环网协议，以ERPS环为基本单位。每台二层交换设备上只能有两个端口加入同一个ERPS环。在ERPS环中，为了防止出现环路，可以启动破除环路机制，阻塞RPL owner端口，消除环路。当环网发生链路故障时，运行ERPS协议的设备可以迅速地放开阻塞端口，进行链路保护倒换，恢复环网上各节点间链路通信。本节主要以示例的形式按照链路正常-&gt;链路故障-&gt;链路恢复的过程（包括保护倒换操作），介绍基本的单环组网下ERPS的实现原理。</p><p>3.4.2.1 链路正常</p><p>如图3-51所示，由Switch A～Switch E组成的环路上各设备通信正常。</p><p><img src="'+pt+'" alt="ERPS链路正常"></p><p align="center"><em>图3-51 ERPS链路正常</em></p><p>为防止环路产生，ERPS首先会阻塞RPL owner端口，如果配置了RPL neighbor端口，该端口同样会被阻塞，其他端口可以正常转发业务流量。</p><p>3.4.2.2 链路故障</p><p>如图3-52所示，当Switch D和Switch E之间的链路发生故障时，ERPS协议启动保护倒换机制，将故障链路的两端端口阻塞，然后放开RPL owner端口，这两个端口重新恢复用户流量的接收和发送，从而保证了流量不中断。</p><p><img src="'+et+'" alt="ERPS链路故障"></p><p align="center"><em>图3-52 ERPS链路故障</em></p><p>3.4.2.3 链路恢复</p><p>链路恢复正常后，默认情况下，ERPS环配置的是回切模式，RPL owner端口所在设备会重新阻塞RPL链路上的流量，原故障链路重新被用来完成用户流量的传送。</p><p>3.4.2.4 ERPS环种类</p><p>单环：</p><p>以图3-53为例，网络拓扑中只有一个环；有且仅有一个RPL Owner；有且仅有一条RPL链路；所有节点需具有相同的RAPS管理VLAN</p><p>环网中所有设备都需要支持ERPS功能。</p><p>环网中的设备之间的链路必须直连，不能有中间设备。</p><p><img src="'+dt+'" alt="ERPS单环模型"></p><p align="center"><em>图3-53 ERPS单环模型</em></p><p>相切环：</p><p>网络拓扑中两个或两个以上共用一台设备的环网需要保护的应用场景。以图3-54为例，网络拓扑中的两个环共用一台设备；每个环有且仅有一个阻断点，每个环有且仅有一条RPL链路；不同环需具有不同的RAPS管理VLAN。</p><p>环网中所有设备都需要支持ERPS功能。</p><p>环网中的设备之间的链路必须直连，不能有中间设备。</p><p><img src="'+rt+'" alt="ERPS相切环模型"></p><p align="center"><em>图3-54 ERPS相切环模型</em></p><p>相交环：</p><p>网络拓扑中有两个或两个以上的环共用一条链路（相交的两个节点间必须直连，不能再有其它节点）。以图3-55为例，网络拓扑中有2个环；每个环有且仅有一个RPL owner节点，每个环有且仅有一条RPL链路；不同环需具有不同的RAPS管理Alan。</p><p>环网中所有设备都需要支持ERPS功能。</p><p>环网中的设备之间的链路必须直连，不能有中间设备。</p><p><img src="'+at+'" alt="ERPS相交环模型"></p><p align="center"><em>图3-55 ERPS相交环模型</em></p><h3 id="erps配置简介" tabindex="-1">ERPS配置简介 <a class="header-anchor" href="#erps配置简介" aria-label="Permalink to &quot;ERPS配置简介&quot;">​</a></h3><p>生成树协议和ERPS协议不能同时开启。</p><p>3.4.3.1 ERPS环配置</p><p>点击导航栏中【配置】【ERPS】【环配置】，进入ERPS环配置界面，如图3-56所示，参数信息具体描述如表3-17所示。</p><p><img src="'+it+'" alt="ERPS环配置界面"></p><p align="center"><em>图3-56 ERPS环配置界面</em></p><p><strong>表3-17 环配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>环编号</td><td>ERPS环ID，可以为任意数字。每个ERPS环的环编号必须唯一。</td></tr><tr><td>东接口</td><td>ERPS环的东向接口</td></tr><tr><td>西接口</td><td>ERPS环的西向接口</td></tr><tr><td>操作</td><td>删除ERPS实例</td></tr></tbody></table><p>3.4.3.2 ERPS实例配置</p><p>点击导航栏中选择【配置】【ERPS】【实例配置】，进入ERPS实例配置界面，如图3-57所示。</p><p><img src="'+nt+'" alt="ERPS实例配置"></p><p align="center"><em>图3-57 ERPS实例配置</em></p><p>点击ERPS“实例配置”下方的【+添加】按钮，进入ERPS实例配置界面，如图3-58所示，实例配置具体参数说明如表3-18描述。</p><p><strong>表3-18 环配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td>实例名称，字符串格式，需要确保唯一，如数字“1”，字符“aa”</td></tr><tr><td>ID</td><td>配置ERPS实例保护的VLAN Instance；默认所有VLAN属于Instance 0；默认id为0。</td></tr><tr><td>环编号</td><td>关联的环ID，必须是已经创建的环</td></tr><tr><td>级别</td><td>ERPS优先级，默认为0</td></tr><tr><td>RAPS管理VLAN</td><td>同一个环中的每台交换机必须配置相同的RAPS管理VLAN，用于传输ERPS协议报文。 RAPS管理VLAN可以是虚拟VLAN，要求与数据VLAN区别即可，不需要实际创建。</td></tr><tr><td>数据VLAN</td><td>ERPS数据VLAN，设置允许在ERPS环中传输的VLAN。必须是已经存在的VLAN，如果不存在请在VLAN配置中新增； 支持VLAN Range类配置，比如“1-3,5”表示VLAN 1,2,3,5；</td></tr><tr><td>Owner接口</td><td>主环ERPS Owner节点，可以选择east接口或者west接口为Owner节点。 每个 ERPS 环有且仅有一个设备配置为 RPL owner 节点，该节点控制需要阻断的端口。</td></tr><tr><td>子环阻断口</td><td>子环阻断口，一个子环只有一个阻断口，可以选择east或者west。 只有在相切环时才需要配置此参数，环相切的两台设备的子环必须设置子环阻断口。</td></tr><tr><td>关联实例</td><td>仅在需要配置子环阻断口时才需要设置，设置为与当前子环相切的环ID。</td></tr></tbody></table><p><img src="'+ot+'" alt="ERPS实例配置"></p><p align="center"><em>图3-58 ERPS实例配置</em></p><h3 id="单环配置举例" tabindex="-1">单环配置举例 <a class="header-anchor" href="#单环配置举例" aria-label="Permalink to &quot;单环配置举例&quot;">​</a></h3><p>案例需求：</p><p>3台交换机组环网，如图3-59所示，配置默认阻断口为S1的GigabitEthernet 0/9口，发生故障时可以及时恢复链路确保网络可用。</p><p><img src="'+st+'" alt="ERPS网络拓扑"></p><p align="center"><em>图3-59 ERPS网络拓扑</em></p><p>3.4.4.1 配置交换机S1</p><p>步骤1：配置端口9和10为trunk口，Native Vlan为缺省值1。</p><p>在导航栏选择【配置】【端口】【端口配置】，进入接口配置界面，点击【批量编辑】按钮，如图3-60所示，选择端口GigabitEthernet 0/9、GigabitEthernet 0/10，端口模式选择“Trunk”，Native VLAN默认为“1”，Allows VLANs为“all”。</p><p><img src="'+gt+'" alt="端口配置界面"></p><p align="center"><em>图3-60 端口配置界面</em></p><p>点击【确认】按钮，返回的接口界面如图3-61所示。</p><p><img src="'+mt+'" alt="端口状态显示界面"></p><p align="center"><em>图3-61 端口状态显示界面</em></p><p>步骤2：创建ERPS环。</p><p>在导航栏中选择【配置】【ERPS】，进入ERPS配置界面，点击换配置下方的【+添加】按钮，进入ERPS环配置界面，如图3-62所示。环编号设置为“1”，东接口设置为“GigabitEthernet 0/9”，西接口设置为“GigabitEthernet 0/10”。RAPS VLAN默认为“1000”，ID默认为“0”，级别默认“0”，Owner接口“East”，子环阻断口“None”。</p><p><img src="'+ct+'" alt="ERPS环配置界面"></p><p align="center"><em>图3-62 ERPS环配置界面</em></p><p>点击【确认】按钮，返回如下页面，如图3-63所示。</p><p><img src="'+lt+'" alt="创建成功的ERPS环"></p><p align="center"><em>图3-63 创建成功的ERPS环</em></p><p>步骤3：点击辅助区的【保存】按钮，保存配置。</p><p>单环情况下，只需要设置一个阻断点就可以，阻断点的选择一般考虑在环的中间。</p><p>3.4.4.2 配置交换机S2和S3</p><p>步骤1：配置端口9和10为trunk口，Native Alan为缺省值1。</p><p>在导航栏选择【配置】【端口】【端口配置】，进入接口配置界面，点击【批量编辑】按钮，如图3-58所示，选择端口GigabitEthernet 0/9、GigabitEthernet 0/10，端口模式选择“Trunk”，Native Vlan默认为“1”，Allows VLANs为“all”，点击【OK】按钮完成配置。</p><p>步骤2：创建ERPS实例</p><p>在导航栏中选择【配置】【ERPS】，进入ERPS配置界面，点击“环配置”下方的【+添加】按钮，进入ERPS环配置界面，环编号设置为“1”，东接口设置为“GigabitEthernet 0/9”，西接口设置为“GigabitEthernet 0/10”。RAPS VLAN默认为“1000”，ID默认为“0”，级别默认“0”，Owner接口“None”，子环阻断口“None”，点击【确认】按钮完成配置。创建成功的ERPS环如图3-64所示。</p><p><img src="'+ht+'" alt="创建成功的ERPS环"></p><p align="center"><em>图3-64 创建成功的ERPS环</em></p><p>步骤3：选择导航栏上的【保存】按钮，保存配置。</p><p>与S1不同的地方，S2和S3在于阻断点Owner接口=None。</p><h2 id="poe" tabindex="-1">PoE <a class="header-anchor" href="#poe" aria-label="Permalink to &quot;PoE&quot;">​</a></h2><h3 id="poe简介" tabindex="-1">PoE简介 <a class="header-anchor" href="#poe简介" aria-label="Permalink to &quot;PoE简介&quot;">​</a></h3><p>PoE（Power over GigabitEthernet ernet，以太网供电，又称远程供电）是指设备通过以太网电口，利用双绞线对外接 PD（Powered Device，受电设备）进行远程供电。</p><p>PoE系统组成</p><p>PoE系统如图3-65所示，包括PoE电源、PSE（Power Sourcing Equipment，供电设备）、PI（Power Interface，电源接口）和PD。</p><p><img src="'+At+'" alt="PoE系统"></p><p align="center"><em>图3-65 PoE系统</em></p><ol><li>PoE电源</li></ol><p>PoE 电源为整个 PoE 系统供电。</p><ol start="2"><li>PSE</li></ol><p>PSE是直接给PD供电的设备。PSE分为内置（Endpoint）和外置（Midspan）两种：内置指的是PSE集成在交换机内部，外置指的是 PSE 与交换机相互独立。我司的PSE均采用内置方式，PSE支持的主要功能包括寻找、检测 PD，对PD分类，并向其供电，进行功率管理，检测与PD的连接是否断开等。</p><ol start="3"><li>PI</li></ol><p>PI是指具备PoE供电能力的以太网接口，也称为PoE接口，包括FE和GE接口。</p><p>PoE接口远程供电有两种模式：</p><p>信号线供电模式：PSE使用3/5 类双绞线中传输数据所用的线对（1、2、3、6）向 PD 传输数据的同时传输直流电。</p><p>空闲线供电模式：PSE 使用 3/5 类双绞线中没有用于数据传输的线对（4、5、7、8）向 PD 来传输直流电。</p><ol start="4"><li>PD</li></ol><p>PD是接受PSE供电的设备，如IP电话、无线AP（Access Point，接入点）、便携设备充电器、刷卡机、网络摄像头等。</p><p>PD设备在接受PoE电源供电的同时，可以连接其它电源，进行电源冗余备份。</p><h3 id="配置poe" tabindex="-1">配置PoE <a class="header-anchor" href="#配置poe" aria-label="Permalink to &quot;配置PoE&quot;">​</a></h3><p>1、在配置PoE功能前，请确保PoE电源或PSE已经处于正常工作状态，否则，可能无法进行PoE配置或者配置的PoE</p><p>功能不能生效。</p><p>2、对于外置电源的交换机，输入电压范围为44-57V，为了获得更稳定的供电，建议AT设备供电电压大于50V，BT设备供电电压大于53V。</p><p>PoE配置步骤：</p><p>（1）在导航栏中选择【配置】【PoE管理】，进入PoE管理界面。</p><p>（2）在PoE全局配置中设置“最大功率”和“保留功率”，点击【应用】完成配置，如图3-66所示。</p><p><img src="'+Pt+'" alt="PoE全局配置"></p><p align="center"><em>图3-66 PoE全局配置</em></p><p>PoE全局配置参数说明，如表3-19所示。</p><p><strong>表3-19 PoE全局配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>总功率</td><td>默认情况下，设备默认提供的功率为15.4W*端口数，如8口设备所能提供的最大功率为123.2W • 外接电源的设备，此参数请根据实际配置的电源功率来填写 • 内置电源的设备，此参数请参考产品手册里对于PoE功率的描述</td></tr><tr><td>保留功率</td><td>为防止电源波动设置的预留功率 • 外接电源的设备，此参数建议填写主板的消耗功率 • 内置电源的设备，此参数可以默认为0</td></tr><tr><td>供电管理</td><td>默认为节能模式，每个端口分配的功率以实际消耗的功率计算，PSE会默认把多余的功率分配给其他端口</td></tr><tr><td>端口模式</td><td>默认为DC disconnect模式</td></tr><tr><td>告警状态</td><td>开启/关闭电源不足时log告警</td></tr><tr><td>告警功率(%)</td><td>告警水线设置，PoE消耗功率超过此水线值时，系统会自动输出log告警</td></tr></tbody></table><p>（3）选择需要配置的端口，点击【编辑】，进入接口配置界面，如图3-67所示。</p><p><img src="'+St+'" alt="PoE接口配置"></p><p align="center"><em>图3-67 PoE接口配置</em></p><p>（4）单击【确定】按钮完成操作，返回PoE主界面，如图3-68所示。</p><p><img src="'+_t+'" alt="PoE接口配置主界面"></p><p align="center"><em>图3-68 PoE接口配置主界面</em></p><p>（5）单击辅助区的【保存】按钮，保存配置。</p><p>PoE端口状态参数说明，如表3-20所示。</p><p><strong>表3-20 PoE参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td>指示面板端口号</td></tr><tr><td>管理状态</td><td>Disabled：关闭端口的PoE供电 Enable：开启端口的PoE供电 Force_on：强制开启端口的PoE供电，该功能的实现方式为跳过PD负载检测和PD分级检 测，直接对PD负载供电。在该模式下，默认最大负载功率为15w，如果需要对大于15w的设 备进行供电，需要同时配置最大功率参数。</td></tr><tr><td>描述</td><td>添加PoE端口的描述</td></tr><tr><td>最大功率</td><td>配置该端口的最大功率。 对于AF/AT端口，端口最大功率范围为1-30 对于BT端口，端口最大功率范围为1-90 默认模式下，该端口将根据PD等级进行功率管理。</td></tr><tr><td>优先级</td><td>配置端口的供电优先级 用户可以配置 PoE 交换机的接口供电优先级。优先级从高到低依次为：high、medium 和 low。 在PoE交换机整机功率不足的时候，低优先级的端口先掉电。 相同优先级的端口优先级按照端口号顺序排列，端口号小的优先级高，比如端口0/1的优先级就 比端口0/2和0/3高。 相同优先级端口，新插入的端口，不会影响到已经处于供电状态的PD设备的供电情况。不同优 先级的端口不受这个特性影响，高优先级端口可以抢占低优先级的端口。</td></tr><tr><td>检测模式</td><td>None：关闭PD检测功能 Flow：开启Flow模式的PD检测功能。此功能通过监控端口计数器实现，如果一段时间内端口 计数器没有改变，则判断为该端口下挂的PD设备处于死机状态，则关闭供电几秒后再开启供 电。 Ping：开启Ping模式的PD检测功能。此功能通过不断对PD负载ping包来实现，如果一段时 间内ping包不通，则判断为该端口下挂的PD设备处于死机状态，则关闭供电几秒后再开启供 电。建议启用此功能前，先用交换机【诊断】网络工具】【ping】来测试PD设备ping包可 达。</td></tr><tr><td>IP地址</td><td>Ping模式下，PD负载的IP地址，要求交换机和PD负载处于同一个网段。</td></tr><tr><td>间隔</td><td>检测模式开启时，检测时间间隔</td></tr><tr><td>次数</td><td>检测模式开启时，检测次数 PD负载的启动时间必须要小于间隔*次数，不然会造成PD负载一直处于启动下电启动这个 状态。</td></tr><tr><td>兼容模式</td><td>ON/OFF，默认为OFF。 OFF：只支持标准的PD设备，检测电阻在19k-26.5k之间，检测电容小于150nF。 ON：支持非标的PD设备，可以对检测电阻和电容值超过标准值之外的部分PD设备进行供电。</td></tr></tbody></table><h2 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h2><h3 id="端口安全" tabindex="-1">端口安全 <a class="header-anchor" href="#端口安全" aria-label="Permalink to &quot;端口安全&quot;">​</a></h3><p>3.6.1.1 概述</p><p>Port Security功能通过对端口合法MAC地址个数限制，达到限制非法用户对该端口访问的目的，对于非法MAC的报文，将直接丢弃。</p><p>合法MAC可通过静态或动态的方式生成。静态合法MAC通过用户命令行配置生成；动态合法MAC则通过MAC地址学习功能动态生成。</p><p>当端口上安全地址个数已经达到最大安全地址个数配置值后，新MAC访问端口将认定为非法MAC，产生违例事件，用户可配置违例事件产生时的应对操作，分别为restrict或shutdown端口。</p><p>Restrict：禁止非法MAC数据通过，并产生告警log提示信息。非法MAC将在MAC地址老化时间内禁止访问端口。通过shutdown、no shutdown端口可恢复。</p><p>Shutdown：强制端口down掉，并可配置端口恢复时间，时间到了端口自动恢复；也可通过shutdown，no shutdown命令恢复。</p><p>若希望将动态安全用户转换为静态安全用户，可开启端口上sticky功能。端口开启sticky功能，端口上学习到的动态用户将以静态用户的方式存在，若保存配置，设备重启后依然存在。</p><p>仅支持L2端口配置端口安全，如普通物理口，聚合口。</p><p>仅支持在access模式下配置端口安全功能。</p><p>不支持聚合口成员口配置端口安全功能。</p><p>不支持SPAN的目的端口配置端口安全功能。</p><p>不支持在已配置静态MAC地址端口配置端口安全功能。</p><p>3.6.1.2 配置端口安全</p><p>端口配置</p><p>在导航栏中选择【配置】【安全】【端口安全】【端口配置】，进入端口配置概况界面，如图3-69所示。</p><p><img src="'+bt+'" alt="端口配置概况"></p><p align="center"><em>图3-69 端口配置概况</em></p><p>点击“端口配置”下方的【批量编辑】按钮，进入端口配置页面，如图3-70所示。端口配置各参数说明如表格3-21所示。</p><p><img src="'+Et+'" alt="端口配置页面"></p><p align="center"><em>图3-70 端口配置页面</em></p><p><strong>表3-21 端口配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>端口配置</td><td>状态</td><td>使能/关闭接口上端口安全功能</td></tr><tr><td>端口配置</td><td>最大MAC数</td><td>配置端口最大安全MAC地址个数，默认最大安全地址个数为1，范围&lt;1-1024&gt;</td></tr><tr><td>端口配置</td><td>Sticky</td><td>开启/关闭Sticky功能</td></tr><tr><td>端口配置</td><td>老化时间</td><td>配置安全地址老化时间，单位分钟。默认老化时间为0，表示关闭老化功能 老化时间范围&lt;0-1440&gt; 默认老化功能仅对动态、sticky安全地址生效</td></tr><tr><td>端口配置</td><td>老化静态地址</td><td>配置使能静态安全地址老化功能</td></tr><tr><td>端口配置</td><td>违例模式</td><td>配置端口安全违例处理，默认违例处理模式restrict Restrict：禁止非法用户数据通过，并log提示 Shutdown：shutdown端口，并在errdisable恢复时间后恢复，通过 shutdown/no shutdown命令，同样可恢复</td></tr></tbody></table><p>MAC配置</p><p>在导航栏中选择【配置】【安全】【端口安全】【MAC配置】，进入MAC配置概况界面，如图3-71所示。</p><p><img src="'+Nt+'" alt="MAC概况界面"></p><p align="center"><em>图3-71 MAC概况界面</em></p><p>点击“MAC配置”下方的【添加】按钮，进入MAC配置页面，如图3-72所示。</p><p><img src="'+Dt+'" alt="MAC配置界面"></p><p align="center"><em>图3-72 MAC配置界面</em></p><p>MAC配置各参数说明如表格3-22所示。</p><p><strong>表3-22 MAC配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>端口配置</td><td>接口</td><td>选择需要配置的接口</td></tr><tr><td>端口配置</td><td>MAC地址</td><td>配置静态安全地址，安全地址格式：XXXX.XXXX.XXXX 安全地址不能是广播或组播地址</td></tr><tr><td>端口配置</td><td>类型</td><td>配置MAC地址为Static或者Sticky</td></tr></tbody></table><p>3.6.1.3 配置举例</p><ol><li>需求</li></ol><p>限制接口GigabitEthernet 0/1合法用户数3个，MAC分别为0001.0001.0001、0001.0001.0002、和0001.0001.0003的非法用户不能访问设备。</p><ol start="2"><li>典型配置举例</li></ol><p>步骤1：在导航栏中选择【配置】【安全】【端口安全】，点击“端口安全”下方的【批量配置】按钮，进入端口配置界面，在端口面板选择GigabitEthernet 0/1，其他配置如下图3-73所示。</p><p><img src="'+It+'" alt="配置端口GigabitEthernet 0/1"></p><p align="center"><em>图3-73 配置端口GigabitEthernet 0/1</em></p><p>步骤2：在当前页面点击“MAC配置”下方的【添加按钮】，进入MAC配置界面，接口选择GigabitEthernet 0/1，在MAC地址对话框输入“0001.0001.0003”，类型选择“Static”，具体配置如下图3-74所示。</p><p><img src="'+Lt+'" alt="MAC配置界面"></p><p align="center"><em>图3-74 MAC配置界面</em></p><p>在MAC地址栏，依次输入三个静态地址，配置成功后的界面如图3-75所示。</p><p><img src="'+ut+'" alt="配置成功的MAC地址"></p><p align="center"><em>图3-75 配置成功的MAC地址</em></p><h3 id="ip-source-guard" tabindex="-1">IP Source Guard <a class="header-anchor" href="#ip-source-guard" aria-label="Permalink to &quot;IP Source Guard&quot;">​</a></h3><p>3.6.2.1 概述</p><p>IP Source Guard：</p><p>Ip Source Guard绑定功能，允许符合IP+MAC绑定的IP报文通过端口，不符合的报文则直接丢弃，从而达到防止IP/MAC欺骗攻击的目的。</p><p>Ip Source Guard的绑定条目，主要有两个来源：用户静态配置与ip dhcp snooping环境中动态获取。</p><p>用户静态配置：主要应对局域网络中IP地址静态配置的主机用户。</p><p>Ip dhcp snooping动态获取：主要应对局域网络中通过dhcp动态获取到IP地址的主机用户。</p><p>IP/MAC欺骗攻击：非法MAC用户，发送带合法源IP的IP报文，实现访问身份的合法化。</p><p>ARP Check：</p><p>Arp-check(ARP 报文检查)功能，对端口下所有的 ARP 报文进行过滤，对所有非法的 ARP 报文进行丢弃，能够有效的防止网络中ARP欺骗，提高网络的稳定性。</p><p>在支持 Arp-check功能的设备中，Arp-check功能能够根据 IP Source Guard等安全应用模块所生成的合法用户信息(IP+MAC)产生相应的ARP过滤信息，从而实现对网络中的非法ARP报文的过滤。</p><p>3.6.2.2 配置IP Source Guard</p><p>步骤1：在导航栏中选择【配置】【安全】【IP Source Guard】，进入IP Source Guard端口配置概况页面，如图3-76所示。</p><p><img src="'+Rt+'" alt="IP Source Guard概况界面"></p><p align="center"><em>图3-76 IP Source Guard概况界面</em></p><p>步骤2：在当前页面，点击“端口配置”下方的【批量配置】按钮，进入IP Source Guard端口配置界面。选中需要配置的端口，点击“Verify Source”开启按钮，如图3-77所示，点击【确认】按钮，完成配置。</p><p><img src="'+Vt+'" alt="IP Source Guard端口配置界面"></p><p align="center"><em>图3-77 IP Source Guard端口配置界面</em></p><p>步骤3：在当前页面，点击“用户配置”下方的【添加】按钮，进入IP Source Guard用户配置界面。选择需要配置的接口、VID，输入MAC地址和IP地址，如图3-78所示。</p><p><img src="'+Ct+'" alt="IP Source Guard用户配置界面"></p><p align="center"><em>图3-78 IP Source Guard用户配置界面</em></p><p>点击【确认】按钮，完成配置，在用户配置界面可以看到创建成功的IP Source Guard规则，如图3-79所示。</p><p><img src="'+Mt+'" alt="创建成功的IP Source Guard规则"></p><p align="center"><em>图3-79 创建成功的IP Source Guard规则</em></p><p>3.6.2.3 配置ARP Check</p><p>步骤1：在导航栏中选择【配置】【安全】【IP Source Guard】，进入IP Source Guard端口配置概况页面。</p><p>步骤2：在当前页面，点击“端口配置”下方的【批量配置】按钮，进入IP Source Guard端口配置界面。选中需要配置的端口，点击“ARP Check”开启按钮，如图3-80所示，点击【确认】按钮，完成配置。</p><p><img src="'+Ut+'" alt="ARP Check端口配置界面"></p><p align="center"><em>图3-80 ARP Check端口配置界面</em></p><p>步骤3：在当前页面，点击“用户配置”下方的【添加】按钮，进入IP Source Guard用户配置界面。选择需要配置的接口、VID，输入MAC地址和IP地址，如图3-81所示。</p><p><img src="'+Tt+'" alt="ARP Check端口配置界面"></p><p align="center"><em>图3-81 ARP Check端口配置界面</em></p><p>点击【应用】按钮，完成配置，在用户配置界面看到创建成功的ARP Check规则，如图3-82所示。</p><p><img src="'+yt+'" alt="创建成功的ARP Check规则"></p><p align="center"><em>图3-82 创建成功的ARP Check规则</em></p><h3 id="dot1x" tabindex="-1">Dot1X <a class="header-anchor" href="#dot1x" aria-label="Permalink to &quot;Dot1X&quot;">​</a></h3><p>3.6.3.1 概述</p><p>最初，IEEE 802 LAN/WAN 委员会为解决无线局域网网络安全问题，提出了802.1X协议。后来，802.1X 协议作为局域网的一个普通接入控制机制在以太网中被广泛应用，主要解决以太网内认证和安全方面的问题。</p><p>802.1X 协议是一种基于端口的网络接入控制协议，即在局域网接入设备的端口上对所接入的用户设备进行认证，以便用户设备控制对网络资源的访问。</p><p>802.1X的体系结构</p><p>802.1X系统中包括三个实体：客户端（Client）、设备端（Device）和认证服务器（Authentication server），如图3-83所示。</p><p><img src="'+wt+'" alt="802.1X体系结构"></p><p align="center"><em>图3-83 802.1X体系结构</em></p><p>客户端是请求接入局域网的用户终端设备，它由局域网中的设备端对其进行认证。客户端上必须安装支持 802.1X 认证的客户端软件。</p><p>设备端是局域网中控制客户端接入的网络设备，位于客户端和认证服务器之间，为客户端提供接入局域网的端口（物理端口或逻辑端口），并通过与服务器的交互来对所连接的客户端进行认证。</p><p>认证服务器用于对客户端进行认证、授权和计费，通常为RADIUS（Remote Authentication Dial-In User Service，远程认证拨号用户服务）服务器。认证服务器根据设备端发送来的客户端认证信息来验证客户端的合法性，并将验证结果通知给设备端，由设备端决定是否允许客户端接入。在一些规模较小的网络环境中，认证服务器的角色也可以由设备端来代替，即由设备端对客户端进行本地认证、授权和计费。</p><p>802.1X对端口的控制</p><p>1、受控/非受控端口</p><p>设备端为客户端提供接入局域网的端口被划分为两个逻辑端口：受控端口和非受控端口。任何到达该端口的帧，在受控端口与非受控端口上均可见。</p><p>非受控端口始终处于双向连通状态，主要用来传递 EAPOL（Extensible Authentication Protocol over LAN，局域网上的可扩展认证协议）协议帧，保证客户端始终能够发出或接收认证报文。</p><p>受控端口在授权状态下处于双向连通状态，用于传递业务报文；在非授权状态下禁止从客户端接收任何报文。</p><p>2、授权/非授权状态</p><p>设备端利用认证服务器对需要接入局域网的客户端执行认证，并根据认证结果（Accept 或 Reject）对受控端口的授权状态进行相应地控制。</p><p><img src="'+kt+'" alt="802.1X认证系统的端口状态。系统 1 的受控端口处于非授权状态，不允许报文通过；系统 2 的受控端口处于授权状态，允许报文通过。"></p><p align="center"><em>图3-84显示了受控端口上不同的授权状态对通过该端口报文的影响。图中对比了两个 802.1X认证系统的端口状态。系统 1 的受控端口处于非授权状态，不允许报文通过；系统 2 的受控端口处于授权状态，允许报文通过。</em></p><p><img src="'+ft+'" alt="受控端口上授权状态的影响"></p><p align="center"><em>图3-84 受控端口上授权状态的影响</em></p><p>3、受控方向</p><p>在非授权状态下，受控端口可以被设置成单向受控和双向受控。</p><p>处于双向受控状态时，禁止帧的发送和接收；</p><p>处于单向受控状态时，禁止从客户端接收帧，但允许向客户端发送帧。</p><p>4.4.1.3 802.1X的认证触发方式</p><p>802.1X 的认证过程可以由客户端主动发起，也可以由设备端发起。</p><p>1、客户端主动触发方式</p><p>组播触发：客户端主动向设备端发送 EAPOL-Start 报文来触发认证，该报文目的地址为组播MAC 地址 01-80-C2-00-00-03。</p><p>广播触发：客户端主动向设备端发送 EAPOL-Start 报文来触发认证，该报文的目的地址为广播MAC地址。该方式可解决由于网络中有些设备不支持上述的组播报文，而造成认证设备无法收到客户端认证请求的问题。</p><p>2、设备端主动触发方式</p><p>设备端主动触发方式用于支持不能主动发送 EAPOL-Start 报文的客户端，例如 Windows XP 自带的</p><p>802.1X 客户端。设备主动触发认证的方式分为以下两种：</p><p>组播触发：设备每隔 N秒（缺省为 30秒）主动向客户端组播发送 Identity类型的 EAP-Request 帧来触发认证。</p><p>单播触发：当设备收到源 MAC 地址未知的报文时，主动向该 MAC 地址单播发送 Identity 类型的 EAP-Request 帧来触发认证。若设备端在设置的时长内没有收到客户端的响应，则重发该报文。</p><p>802.1X的认证过程</p><p>802.1X 系统支持采用 EAP 中继方式和 EAP 终结方式与远端 RADIUS 服务器交互。</p><p>EAP中继方式</p><p>这种方式是 IEEE 802.1X 标准规定的，将 EAP 承载在其它高层协议中，如 EAP over RADIUS，以便扩展认证协议报文穿越复杂的网络到达认证服务器。一般来说，需要 RADIUS 服务器支持 EAP 属性：EAP-Message 和 Message-Authenticator，分别用来封装 EAP 报文及对携带 EAP-Message 的 RADIUS 报文进行保护。</p><p>下面以MD5-Challenge认证方法为例介绍基本业务流程，认证过程如图3-85所示。</p><p><img src="'+qt+'" alt="IEEE 802.1X 认证系统的 EAP 中继方式业务流程"></p><p align="center"><em>图3-85 IEEE 802.1X 认证系统的 EAP 中继方式业务流程</em></p><p>当用户需要访问外部网络时打开802.1X客户端程序，输入已经申请、登记过的用户名和密码，发起连接请求。此时，客户端程序将向设备端发出认证请求帧（EAPOL-Start），开始启动一次认证过程。</p><p>设备端收到认证请求帧后，将发出一个 Identity 类型的请求帧（EAP-Request/Identity）要求用户的客户端程序发送输入的用户名。</p><p>客户端程序响应设备端发出的请求，将用户名信息通过 Identity 类型的响应帧（EAP-Response/Identity）发送给设备端。</p><p>设备端将客户端发送的响应帧中的 EAP 报文封装在 RADIUS 报文（RADIUS Access-Request）中发送给认证服务器进行处理。</p><p>RADIUS 服务器收到设备端转发的用户名信息后，将该信息与数据库中的用户名列表中对比，找到该用户名对应的密码信息，用随机生成的一个 MD5 Challenge 对密码进行加密处理，同时将此 MD5 Challenge 通过 RADIUS Access-Challenge 报文发送给设备端。</p><p>设备端将 RADIUS 服务器发送的 MD5 Challenge 转发给客户端。</p><p>客户端收到由设备端传来的 MD5 Challenge 后，用该 Challenge 对密码部分进行加密处理，生成 EAP-Response/MD5 Challenge 报文，并发送给设备端。</p><p>设备端将此 EAP-Response/MD5 Challenge 报文封装在 RADIUS 报文（RADIUS Access-Request）中发送给 RADIUS 认证服务器。</p><p>RADIUS 服务器将收到的已加密的密码信息和本地经过加密运算后的密码信息进行对比，如果相同，则认为该用户为合法用户，并向设备端发送认证通过报文（RADIUS Access-Accept）。</p><p>设备收到认证通过报文后向客户端发送认证成功帧（EAP-Success），并将端口改为授权状态，允许用户通过端口访问网络。</p><p>用户在线期间，设备端会通过向客户端定期发送握手报文的方法，对用户的在线情况进行监测。</p><p>客户端收到握手报文后，向设备发送应答报文，表示用户仍然在线。缺省情况下，若设备端发送的两次握手请求报文都未得到客户端应答，设备端就会让用户下线，防止用户因为异常原因下线而设备无法感知。</p><p>客户端可以发送 EAPOL-Logoff 帧给设备端，主动要求下线。</p><p>设备端把端口状态从授权状态改变成未授权状态，并向客户端发送 EAP-Failure 报文。</p><p>EAP 中继方式下，需要保证在客户端和 RADIUS 服务器上选择一致的 EAP 认证方法，而在设备上，只需要配置</p><p>802.1X 用户的认证方式为 EAP 即可。</p><p>802.1X的接入控制方式</p><p>设备不仅支持协议所规定的基于端口的接入认证方式（Port Based），还对其进行了扩展、优化，支持基于 MAC 的接入控制方式（MAC Based）。</p><p>当采用基于端口的接入控制方式时，只要该端口下的第一个用户认证成功后，其它接入用户无须认证就可使用网络资源，但是当第一个用户下线后，其它用户也会被拒绝使用网络。</p><p>采用基于MAC的接入控制方式时，该端口下的所有接入用户均需要单独认证，当某个用户下线时，也只有该用户无法使用网络。</p><p>3.6.3.2 配置802.1X</p><p>查看802.1X概况</p><p>在导航栏中选择【配置】【安全】【Dot1x】，进入Dot1x概况界面，如图3-86所示。在概况界面中可以显示802.1X配置情况，各参数说明如表格3-23所示。</p><p><img src="'+xt+'" alt="802.1X概况界面"></p><p align="center"><em>图3-86 802.1X概况界面</em></p><p><strong>表3-23 802.1X概况参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>全局配置</td><td>状态</td><td>功能开关</td></tr><tr><td>全局配置</td><td>RADIUS配置</td><td>点击跳转到RADIUS配置界面</td></tr><tr><td>端口配置</td><td>名称</td><td>物理端口</td></tr><tr><td>端口配置</td><td>端口受控</td><td>端口受控模式</td></tr><tr><td>端口配置</td><td>协议版本</td><td>使用的802.1X协议版本</td></tr><tr><td>端口配置</td><td>静默时间</td><td>设置静默定时器的值，当802.1X用户认证失败以后，设备需要静默一段时间（通过“静默时长”设定）后再重新发起认证。在静默期间，设备不进行802.1X认证的相关处理。</td></tr><tr><td>端口配置</td><td>发送周期</td><td>报文重传周期</td></tr><tr><td>端口配置</td><td>重认证周期</td><td>设置周期性重认证定时器的值 当端口上启用了周期性重认证功能时，设备端会在用户认证成功后启动周期性重认证定时器，用于周期性的对在线用户发起重认证，以便定时更新服务器对用户的授权信息</td></tr><tr><td>端口配置</td><td>客户端超时时间</td><td>设置客户端超时定时器的值 当设备端向客户端发送了EAP-Request/MD5 Challenge请求报文后，设备端启动此定时器，若在该定时器设置的时长内，设备端没有收到客户端的响应，设备端将重发该报文</td></tr><tr><td>端口配置</td><td>服务器超时时间</td><td>设置服务器超时定时器的值 当设备端向认证服务器发送了RADIUS Access-Request请求报文后，设备端启动服务器超时定时器，若在该定时器设置的时长内，设备端没有收到认证服务器的响应，设备端将重发认证请求报文</td></tr></tbody></table><p>3.6.3.3 802.1X配置举例</p><p>场景需求</p><p>要求在端口GigabitEthernet 0/3上对接入用户进行认证，以控制其访问Internet。</p><p>RADIUS服务器组IP地址1.1.1.2。</p><p>设置系统与RADIUS服务器交互报文时的共享密钥为name。</p><p>组网图</p><p><img src="'+Gt+'" alt="802.1X认证典型组网图"></p><p align="center"><em>图3-87 802.1X认证典型组网图</em></p><p>典型配置举例</p><p>步骤1：配置服务器端</p><p>服务器端：</p><p>配置NAS认证设备1.1.1.1及通信密钥name。</p><p>本例中使用freeradius作为服务器，主要配置如下：</p><h1 id="vim-etc-freeradius-3-0-clients-conf" tabindex="-1">vim /etc/freeRADIUS/3.0/clients.conf <a class="header-anchor" href="#vim-etc-freeradius-3-0-clients-conf" aria-label="Permalink to &quot;vim /etc/freeRADIUS/3.0/clients.conf&quot;">​</a></h1><p>添加</p><p>client 1.1.1.1 {</p><p>ipaddr = 1.1.1.1</p><p>secret = name</p><p>}</p><p>添加用户账户test密码test。</p><h1 id="cat-etc-freeradius-3-0-mods-config-files-authorize-grep-password" tabindex="-1">cat /etc/freeRADIUS/3.0/mods-config/files/authorize | grep &quot;password&quot; <a class="header-anchor" href="#cat-etc-freeradius-3-0-mods-config-files-authorize-grep-password" aria-label="Permalink to &quot;cat /etc/freeRADIUS/3.0/mods-config/files/authorize | grep &quot;password&quot;&quot;">​</a></h1><p>testing Cleartext-Password := &quot;password&quot;</p><p>需要支持对应的认证方法，比如EAP-MSCHAPv2</p><p>步骤2：配置RADIUS服务器。</p><p>在导航栏中选择【配置】【安全】【RADIUS】，进入如图3-88所示页面。</p><p><img src="'+vt+'" alt="RADIUS服务器概况界面"></p><p align="center"><em>图3-88 RADIUS服务器概况界面</em></p><p>点击“服务器”下方的【添加】按钮，进入RADIUS服务器配置界面，如图3-89所示，配置RADIUS服务器IP为1.1.1.2，认证端口默认为1812，输入密码，超时时间为默认5S，重传次数为3，点击【确认】按钮完成配置。</p><p><img src="'+Xt+'" alt="RADIUS服务器配置界面"></p><p align="center"><em>图3-89 RADIUS服务器配置界面</em></p><p>配置完成后，自动返回如下界面，如图3-90所示，可以看到创建成功的RADIUS服务器。</p><p><img src="'+Ot+'" alt="RADIUS服务器显示界面"></p><p align="center"><em>图3-90 RADIUS服务器显示界面</em></p><p>步骤3：开启802.1X认证全局使能。</p><p>在导航栏中选择【配置】【安全】【Dot1x】，进入如图3-91所示页面，点击“状态”【启用/禁用】按钮，，点击【应用】按钮开启802.1X认证。</p><p><img src="'+Bt+'" alt="802.1X全局配置界面"></p><p align="center"><em>图3-91 802.1X全局配置界面</em></p><p>步骤4：配置交换机端口3开启802.1X认证全局使能。</p><p>在当前界面下，点击“端口配置”下方的【批量配置】按钮，进入802.1X端口配置页面，开启端口受控，协议版本为“2”，端口面板选择GigabitEthernet 0/3，如图3-92所示。</p><p><img src="'+Ft+'" alt="802.1X端口配置界面"></p><p align="center"><em>图3-92 802.1X端口配置界面</em></p><p>点击【确认】按钮完成配置，自动返回如下界面，如图3-93所示，可以看到创建成功的条例。</p><p><img src="'+Ht+'" alt="802.1X端口配置显示界面"></p><p align="center"><em>图3-93 802.1X端口配置显示界面</em></p><p>步骤5：配置认证客户端</p><p>开启802.1X认证客户端，使用账户test登录。</p><p>需要支持对应的认证方法，比如EAP-MSCHAPv2方法。</p><h3 id="mac认证" tabindex="-1">MAC认证 <a class="header-anchor" href="#mac认证" aria-label="Permalink to &quot;MAC认证&quot;">​</a></h3><p>3.6.4.1 概述</p><p>MAC地址认证简介</p><p>MAC 地址认证是一种基于端口和 MAC 地址对用户的网络访问权限进行控制的认证方法，它不需要用户安装任何客户端软件。设备在启动了MAC地址认证的端口上首次检测到用户的MAC地址以后，即启动对该用户的认证操作。认证过程中，不需要用户手动输入用户名或者密码。若该用户认证成功，则允许其通过端口访问网络资源，否则该用户的 MAC 地址就被添加为静默 MAC。在静默时间内（可通过静默定时器配置），来自此 MAC 地址的用户报文到达时，设备直接做丢弃处理，以防止非法 MAC 短时间内的重复认证。</p><p>若配置的静态 MAC与静默 MAC 相同，则 MAC 地址认证失败后的MAC 静默功能将会失效。</p><p>目前设备支持MAC 地址认证：</p><p>通过 RADIUS（Remote Authentication Dial-In User Service，远程认证拨号用户服务）服务器进行远程认证。</p><p>目前，MAC 地址认证支持两种类型的用户名格式：</p><p>MAC 地址用户名：使用用户的 MAC 地址作为认证时的用户名和密码。</p><p>RADIUS服务器认证方式进行MAC地址认证</p><p>当选用 RADIUS 服务器认证方式进行 MAC 地址认证时，设备作为 RADIUS 客户端，与 RADIUS 服务器配合完成 MAC 地址认证操作：</p><p>采用 MAC 地址用户名时，设备将检测到的用户 MAC 地址作为用户名和密码发送给 RADIUS 服务器。</p><p>采用固定用户名时，设备将已经在本地配置的用户名和密码作为待认证用户的用户名和密码，发送给 RADIUS 服务器。</p><p>RADIUS 服务器完成对该用户的认证后，认证通过的用户可以访问网络。</p><p>MAC地址认证定时器</p><p>MAC 地址认证过程受以下定时器的控制：</p><p>认证超时定时器：用来设置设备同 RADIUS 服务器的连接超时时间。在用户的认证过程中，如果认证超时定时器超时时设备一直没有收到 RADIUS 服务器的应答，则设备将在相应的端口上禁止此用户访问网络。</p><p>3.6.4.2 配置MAC认证</p><p>查看MAC认证概况</p><p>在导航栏中选择【配置】【安全】【MAC认证】，进入MAC认证概况界面，如图3-94所示页面。在“概况”中可以显示MAC认证配置情况，各参数说明如表格3-24所示。</p><p><img src="'+Wt+'" alt="MAC认证概况界面"></p><p align="center"><em>图3-94 MAC认证概况界面</em></p><p><strong>表3-24 MAC概况参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>全局配置</td><td>状态</td><td>功能开关</td></tr><tr><td>全局配置</td><td>RADIUS配置</td><td>点击跳转到RADIUS配置界面</td></tr><tr><td>端口配置</td><td>名称</td><td>端口名称</td></tr><tr><td>端口配置</td><td>状态</td><td>功能状态，开启或关闭</td></tr><tr><td>端口配置</td><td>MAC地址老化</td><td>是否启用MAC老化功能</td></tr><tr><td>端口配置</td><td>操作</td><td>点击编辑该条例</td></tr></tbody></table><p>配置MAC认证</p><p>在导航栏中选择“安全 &gt; MAC认证 &gt; 配置 ”，进入如图3-95所示页面。在此页面，可以进行802.1X的全局配置以及基于各个端口的配置。配置参数说明如表格3-25所示。</p><p><img src="'+Kt+'" alt="MAC认证配置界面"></p><p align="center"><em>图3-95 MAC认证配置界面</em></p><p><strong>表3-25 MAC概况参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>端口配置</td><td>状态</td><td>开启/关闭此功能</td></tr><tr><td>端口配置</td><td>MAC地址老化</td><td>是否启用MAC老化功能</td></tr></tbody></table><h3 id="radius" tabindex="-1">RADIUS <a class="header-anchor" href="#radius" aria-label="Permalink to &quot;RADIUS&quot;">​</a></h3><p>3.6.5.1 概述</p><p>RADIUS（Remote Authentication Dial-In User Service，远程认证拨号用户服务）是实现AAA （Authentication, Authorization and Accounting，认证、授权和计费）的一种常用的协议。</p><p>RADIUS简介</p><p>RADIUS 是一种分布式的、客户端/服务器结构的信息交互协议，能保护网络不受未授权访问的干扰，常应用在既要求较高安全性、又允许远程用户访问的各种网络环境中。该协议定义了 RADIUS 的报文格式及其消息传输机制，并规定使用 UDP 作为封装 RADIUS 报文的传输层协议（UDP 端口 1812、1813 分别作为认证、计费端口）。</p><p>RADIUS 初仅是针对拨号用户的 AAA 协议，后来随着用户接入方式的多样化发展，RADIUS 也适应多种用户接入方式，如以太网接入、ADSL 接入。它通过认证授权来提供接入服务，通过计费来收集、记录用户对网络资源的使用。</p><p>客户端/服务器模式</p><p>客户端：RADIUS 客户端一般位于 NAS 设备上，可以遍布整个网络，负责传输用户信息到指定的 RADIUS 服务器，然后根据从服务器返回的信息进行相应处理（如接受/拒绝用户接入）。</p><p>服务器：RADIUS 服务器一般运行在中心计算机或工作站上，维护相关的用户认证和网络服务访问信息，负责接收用户连接请求并认证用户，然后给客户端返回所有需要的信息（如接受/拒绝认证请求）。</p><p>RADIUS服务器通常要维护三个数据库，如图3-96所示。</p><p><img src="'+zt+'" alt="RADIUS服务器的组成创建成功的MAC认证端口"></p><p align="center"><em>图3-96 RADIUS服务器的组成创建成功的MAC认证端口</em></p><p>“Users”：用于存储用户信息（如用户名、口令以及使用的协议、IP 地址等配置信息）。</p><p>“Clients”：用于存储 RADIUS 客户端的信息（如接入设备的共享密钥、IP 地址等）。</p><p>“Dictionary”：用于存储 RADIUS 协议中的属性和属性值含义的信息。</p><p>安全和认证机制</p><p>RADIUS 客户端和 RADIUS 服务器之间认证消息的交互是通过共享密钥的参与来完成的，并且共享密钥不能通过网络来传输，增强了信息交互的安全性。另外，为防止用户密码在不安全的网络上传递时被窃取，在传输过程中对密码进行了加密。</p><p>RADIUS 服务器支持多种方法来认证用户，如基于 PPP 的 PAP、CHAP 认证。另外，RADIUS 服务器还可以作为一个代理，以 RADIUS 客户端的身份与其它的 RADIUS 认证服务器进行通信，负责转发 RADIUS 认证和计费报文。</p><p>RADIUS的基本消息交互流程</p><p>用户、RADIUS客户端和RADIUS服务器之间的交互流程如图3-97所示。</p><p><img src="'+$t+'" alt="RADIUS 的基本消息交互流程"></p><p align="center"><em>图3-97 RADIUS 的基本消息交互流程</em></p><p>消息交互流程如下：</p><p>用户发起连接请求，向 RADIUS 客户端发送用户名和密码。</p><p>RADIUS 客户端根据获取的用户名和密码，向 RADIUS 服务器发送认证请求包（Access-Request），其中的密码在共享密钥的参与下由 MD5 算法进行加密处理。</p><p>RADIUS 服务器对用户名和密码进行认证。如果认证成功，RADIUS 服务器向 RADIUS 客户端发送认证接受包（Access-Accept）；如果认证失败，则返回认证拒绝包（Access-Reject）。由于 RADIUS 协议合并了认证和授权的过程，因此认证接受包中也包含了用户的授权信息。</p><p>RADIUS 客户端根据接收到的认证结果接入/拒绝用户。如果允许用户接入，则 RADIUS 客户端向 RADIUS 服务器发送计费开始请求包（Accounting-Request）。</p><p>RADIUS 服务器返回计费开始响应包（Accounting-Response），并开始计费。</p><p>用户开始访问网络资源；</p><p>用户请求断开连接，RADIUS 客户端向 RADIUS 服务器发送计费停止请求包（Accounting-Request）。</p><p>RADIUS 服务器返回计费结束响应包（Accounting-Response），并停止计费。</p><p>用户结束访问网络资源。</p><p>我司设备不支持RADIUS计费功能</p><p>3.6.5.2 配置RADIUS</p><p>RADIUS全局配置</p><p>在导航栏中选择【配置】【安全】【RADIUS】，进入RADIUS全局配置界面，如图3-98所示。全局配置各参数说明如表格3-26所示。</p><p><img src="'+jt+'" alt="RADIUS全局配置界面"></p><p align="center"><em>图3-98 RADIUS全局配置界面</em></p><p><strong>表3-26 RADIUS全局配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>全局配置</td><td>密码</td><td>全局默认密码配置；可配置，不可读；可选配置</td></tr><tr><td>全局配置</td><td>超时</td><td>全局服务器超时时间；可选配置</td></tr><tr><td>全局配置</td><td>重传</td><td>全局服务器重传次数；可选配置</td></tr><tr><td>全局配置</td><td>死亡时间</td><td>服务器死亡持续时间；可选配置；默认0，表示服务器死亡后立即复活</td></tr></tbody></table><p>RADIUS服务器配置</p><p>在当前界面，点击“服务器配置”下方的【添加】按钮，进入服务器配置界面，如图3-99所示。服务器各参数说明如表格3-27所示。</p><p><img src="'+Jt+'" alt="RADIUS服务器配置界面"></p><p align="center"><em>图3-99 RADIUS服务器配置界面</em></p><p><strong>表3-27 MAC概况参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>IP</td><td>服务器IP地址</td></tr><tr><td>认证端口</td><td>服务器认证端口号；默认1812</td></tr><tr><td>密码</td><td>服务器密钥；无配置的时候采用全局配置</td></tr><tr><td>超时</td><td>服务器超时时间；默认5s</td></tr><tr><td>重传</td><td>服务器重传次数，默认3次</td></tr></tbody></table><h2 id="控制" tabindex="-1">控制 <a class="header-anchor" href="#控制" aria-label="Permalink to &quot;控制&quot;">​</a></h2><h3 id="串口服务器" tabindex="-1">串口服务器 <a class="header-anchor" href="#串口服务器" aria-label="Permalink to &quot;串口服务器&quot;">​</a></h3><p>3.7.1.1 概述</p><p>串口服务器：serial device servers。</p><p>串口服务器作用于将串口设备接入到以太网中。串口服务器支持网络数据与串口数据的双向转换、传输。</p><p>tcp-client工作模式</p><p>TCP Client为TCP网络服务提供客户端连接。主动发起连接并连接服务器，用于实现串口数据和服务器数据的交互；网络与串口数据双向透传；串口服务器支持建立多个TCP Client与多个Tcp Server连接。</p><p>tcp-server工作模式</p><p>TCP Server 即 TCP 服务器。在 TCP Server 模式下，模块监听本机端口，有连接请求发来时接 受并建立连接进行数据通信，当模块串口收到数据后会同时将数据发送给所有与模块建立 连接的客户端设备；通常用于局域网内与 TCP 客户端的通信。适合于局域网内没有服务器并且有多台电脑或是手机向模块请求数据的场景。</p><p>3.7.1.2 配置串口服务器</p><p>在导航栏中选择【配置】【控制】【串口服务器】，进入串口服务器配置界面，如图3-100所示。</p><p><img src="'+Qt+'" alt="串口服务器配置界面"></p><p align="center"><em>图3-100 串口服务器配置界面</em></p><p>点击串口ID的【编辑】按钮，进入详细配置界面，如图3-101所示，配置参数如表3-28所示。</p><p><strong>表3-28 串口服务器参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>基础</td><td>ID</td><td>串口服务器端口号</td></tr><tr><td>模式</td><td>None</td><td>关闭串口服务器</td></tr><tr><td>模式</td><td>tcp-client</td><td>配置工作模式为tcp-client</td></tr><tr><td>模式</td><td>tcp-server</td><td>配置工作模式为tcp-server</td></tr><tr><td>串口</td><td>波特率</td><td>配置串口的波特率，有9600、19200、38400、57600、115200五种可选</td></tr><tr><td>串口</td><td>数据位</td><td>配置串口的数据位，有7、8两种可选</td></tr><tr><td>串口</td><td>校验</td><td>配置校验方式，有none、even、odd、mark、space五种可选</td></tr><tr><td>串口</td><td>停止位</td><td>配置停止位，有1、2两种可选</td></tr><tr><td>通信</td><td>缓冲区大小</td><td>串口数据位低速传输，数据从网络端转串口端增加 fifo ，提高转发能力，范围&lt;0-128&gt;，默认64</td></tr><tr><td>通信</td><td>最大报文长度</td><td>串口数据报文长度，超出LENGTH值则分包转发到网络端，范围&lt;0-1460&gt;，默认1460</td></tr><tr><td>通信</td><td>间隔</td><td>串口数据前后字节间隔时间超出MILLISECONDS，则后字节数据认定为新报文头字节 范围&lt;1-1000&gt;，默认10ms</td></tr><tr><td>通信</td><td>保活检测时间</td><td>配置串口服务器保活时间，在该时间段内无数据交互，则启动alive检测</td></tr><tr><td>客户端</td><td>远端IP</td><td>配置远端连接IP地址</td></tr><tr><td>客户端</td><td>远端端口</td><td>配置远端连接的端口号，范围&lt;1-65535&gt;</td></tr><tr><td>客户端</td><td>本地端口</td><td>为可选配置，默认系统自动分配</td></tr><tr><td>服务器</td><td>端口</td><td>配置tcp-server的端口号，范围&lt;1-65535&gt;</td></tr><tr><td>服务器</td><td>最大连接数</td><td>tcp-server模式下最大连接数，范围&lt;1-65535&gt;</td></tr></tbody></table><p><img src="'+Yt+'" alt="串口服务器配置界面"></p><p align="center"><em>图3-101 串口服务器配置界面</em></p><p>3.7.1.3 配置举例</p><p>案例需求1：</p><p>如图3-102所示，配置串口服务器工作在tcp-server模式；配置本地端口号2000；配置最大连接数为3。 TCP Client0/1/2接入到server。</p><p>串口参数baud-rate 115200；data-bits 8；parity none；stop-bits 1，均为默认值。</p><p><img src="'+Zt+'" alt="串口服务器配置界面"></p><p align="center"><em>图3-102 串口服务器配置界面</em></p><p>配置步骤：</p><p>（1）在导航栏中选择【配置】【控制】【串口服务器】，进入串口服务器配置界面。</p><p>（2）点击串口ID的【编辑】按钮，进入详细配置界面，配置参数如图3-103所示，点击【确认】按钮完成配置。</p><p><img src="'+tp+'" alt="串口服务器配置界面"></p><p align="center"><em>图3-103 串口服务器配置界面</em></p><p>案例需求2：</p><p><img src="'+pp+'" alt="串口服务器配置界面"></p><p align="center"><em>图3-104 串口服务器配置界面</em></p><p>TCP Server的IP地址192.168.56.2，端口号2000。</p><p>配置串口服务器工作在tcp-client模式；配置tcp-client 1连接目标TCP Server，本地端口由系统动态生成。</p><p>串口参数baud-rate 115200；data-bits 8；parity none；stop-bits 1，均为默认值。</p><p>配置步骤：</p><p>（1）在导航栏中选择【配置】【控制】【串口服务器】，进入串口服务器配置界面。</p><p>（2）点击串口ID的【编辑】按钮，进入详细配置界面，配置参数如图3-105所示，点击【确认】按钮完成配置。</p><p><img src="'+ep+'" alt="串口服务器配置界面"></p><p align="center"><em>图3-105 串口服务器配置界面</em></p><h3 id="继电器告警" tabindex="-1">继电器告警 <a class="header-anchor" href="#继电器告警" aria-label="Permalink to &quot;继电器告警&quot;">​</a></h3><p>3.7.2.1 概述</p><p>继电器告警（Relay Warning）功能通过在前面板上为外部报警设备提供数字输入DI和数字输出DO（Relay），帮助网络管理员有效地管理意外的网络情况。数字输入DI可用于检测和记录外部设备的状态，如门禁入侵检测器。数字输出DO可用于设备端口链路中断、系统温度异常、PoE状态异常，电源异常时发出警报。</p><p>交换机的数字输入DI可由感测物理变化的外部传感器激活，这些变化包括入侵检测或监控区域的某些物理变化，DI参数说明如表格3-29所示。</p><p><strong>表3-29 DI参数说明</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>触发条件</th><th>描述</th></tr></thead><tbody><tr><td>DI输入</td><td>Low level</td><td>低电平输入触发告警，电压范围“-30V-3V”</td></tr><tr><td>DI输入</td><td>High level</td><td>高电平输入触发告警，电压范围“12V-30V”</td></tr></tbody></table><p>设备可通过DI输入实时检测，触发部分设备内部事件处理，参数说明如表格3-30所示：</p><p><strong>表3-30 内部事件处理参数说明</strong></p><table tabindex="0"><thead><tr><th>触发条件</th><th>事件种类</th><th>描述</th></tr></thead><tbody><tr><td>DI输入： 低电平高电平</td><td>端口事件</td><td>端口shutdown后重新up</td></tr><tr><td>DI输入： 低电平高电平</td><td>端口事件</td><td>端口shutdown</td></tr><tr><td>DI输入： 低电平高电平</td><td>端口PoE事件</td><td>端口PoE下电后重新上电</td></tr><tr><td>DI输入： 低电平高电平</td><td>端口PoE事件</td><td>端口PoE下电</td></tr><tr><td>DI输入： 低电平高电平</td><td>DO输出事件</td><td>继电器常开</td></tr><tr><td>DI输入： 低电平高电平</td><td>DO输出事件</td><td>继电器常闭</td></tr><tr><td>DI输入： 低电平高电平</td><td>DO输出事件</td><td>继电器常开/常闭周期交替</td></tr></tbody></table><p>数字输出DO的主要功能是允许交换机自动、人工或软件应用程序的远程控制触发外部设备，DO的工作状态如表格3-31所示：</p><p><strong>表3-31 DO状态说明</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>模式</th><th>描述</th></tr></thead><tbody><tr><td>继电器输出</td><td>Normally open</td><td>默认为闭合状态，告警触发后为常开状态</td></tr><tr><td>继电器输出</td><td>Normally closed</td><td>默认为常开状态，告警触发后为闭合状态</td></tr><tr><td>继电器输出</td><td>Pulse</td><td>默认情况下，输出为常开状态，告警触发后，输出状态为常开/闭合周期交替，默认周期2秒，占空比50%</td></tr></tbody></table><p>交换机不仅可以人工配置输出状态，也可以关联设备内部事件，触发继电器输出告警，内部事件参数说明如表格3-32所示：</p><p><strong>表3-32 触发继电器输出告警参数说明</strong></p><table tabindex="0"><thead><tr><th>事件</th><th>动作</th><th>动作</th></tr></thead><tbody><tr><td>环境温度</td><td>当环境温度超出配置范围，触发继电器输出告警，</td><td>此功能需要外接相关传感器</td></tr><tr><td>环境湿度</td><td>当环境湿度超出配置范围，触发继电器输出告警</td><td>此功能需要外接相关传感器</td></tr><tr><td>系统温度</td><td>当系统温度超出配置范围，触发继电器输出告警</td><td>当系统温度超出配置范围，触发继电器输出告警</td></tr><tr><td>PoE消耗功率</td><td>当系统PoE消耗功率超出配置百分比时，触发继电器输出告警</td><td>当系统PoE消耗功率超出配置百分比时，触发继电器输出告警</td></tr><tr><td>PoE电压</td><td>当PoE芯片电压超出配置值时，触发继电器输出告警</td><td>当PoE芯片电压超出配置值时，触发继电器输出告警</td></tr><tr><td>PoE温度</td><td>当PoE芯片温度超出配置范围，触发继电器输出告警</td><td>当PoE芯片温度超出配置范围，触发继电器输出告警</td></tr><tr><td>PoE端口供电状态</td><td>当PoE供电端口下电或上电时，触发继电器告警输出</td><td>当PoE供电端口下电或上电时，触发继电器告警输出</td></tr><tr><td>端口状态</td><td>当端口从up变为down或从down变为up时，触发继电器告警输出</td><td>当端口从up变为down或从down变为up时，触发继电器告警输出</td></tr></tbody></table><p>3.7.2.2 继电器告警配置</p><p>在导航栏中选择【配置】【继电器告警】，进入继电器告警配置界面。此页面包含“全局配置”、“触发继电器报警”、“DI口配置”三部分。</p><p>全局配置</p><p>在导航栏中选择【配置】【继电器告警】【全局配置】，进入继电器告警全局配置界面，全局配置界面如图3-106所示，参数说明如表3-33所示。</p><p><strong>表3-33 继电器告警全局配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>环境温度(℃)</td><td>Min：告警低值，环境温度低于低值，触发告警 Max：告警高值，环境温度高于高值，触发告警 默认低值-40℃，默认高值85℃，要求门限低值与高值相差大于5℃ 当环境温度高于高值，触发告警，当温度下降到低于高值2℃时，提示恢复正常 当环境温度低于低值，触发告警，当温度上升到高于低值2℃时，提示恢复正常</td></tr><tr><td>环境湿度(%)</td><td>Threshold(%)：环境湿度告警值，默认值95%；当环境湿度高于告警值，触发告警，当湿度下降到低于告警值2%时，提示恢复正常</td></tr><tr><td>系统温度(℃)</td><td>Min：告警低值，环境温度低于低值，触发告警 Max：告警高值，环境温度高于高值，触发告警 默认低值-40℃，默认高值125℃，要求门限低值与高值相差大于5℃ 当系统温度高于高值，触发告警，当温度下降到低于高值2℃时，提示恢复正常 当系统温度低于低值，触发告警，当温度上升到高于低值2℃时，提示恢复正常</td></tr><tr><td>PoE温度(℃)</td><td>Min：告警低值，环境温度低于低值，触发告警 Max：告警高值，环境温度高于高值，触发告警 默认低值-20℃，默认高值125℃，要求门限低值与高值相差大于5℃ 当PoE温度高于高值，触发告警，当温度下降到低于高值2℃时，提示恢复正常 当PoE温度低于低值，触发告警，当温度上升到高于低值2℃时，提示恢复正常</td></tr><tr><td>PoE电压(V)</td><td>Min：告警低值，PoE电压低于低值，触发告警 Max：告警高值，PoE电压高于高值，触发告警 默认低值44V，默认高值57V，要求门限低值与高值相差大于5V 当PoE电压高于高值，触发告警，当电压下降到低于高值1V时，提示恢复正常 当PoE电压低于低值，触发告警，当电压上升到高于低值1V时，提示恢复正常</td></tr><tr><td>PoE已用功率(%)</td><td>Threshold(%)：PoE消耗功率告警值，默认值80%，即PoE消耗功率达到总功率80%时，触发告警 当PoE消耗功率高于告警值，触发告警，当消耗功率下降到低于告警值2%时，提 示恢复正常</td></tr><tr><td>告警日志使能</td><td>开启/关闭告警日志，默认开启</td></tr><tr><td>告警Trap使能</td><td>开启/关闭trap，默认关闭</td></tr></tbody></table><p><img src="'+dp+'" alt="继电器告警全局配置"></p><p align="center"><em>图3-106 继电器告警全局配置</em></p><p>触发继电器报警</p><p>在导航栏中选择【配置】【继电器告警】【触发继电器报警】，进入触发继电器报警配置界面，如图3-107所示，告警端口行为配置界面如图3-108所示，告警PoE行为配置界面如图3-109所示，触发继电器报警配置参数如表3-34所示。</p><p><img src="'+rp+'" alt="触发继电器报警配置界面"></p><p align="center"><em>图3-107 触发继电器报警配置界面</em></p><p><img src="'+ap+'" alt="告警端口行为配置界面"></p><p align="center"><em>图3-108 告警端口行为配置界面</em></p><p><img src="'+ip+'" alt="告警PoE行为配置界面"></p><p align="center"><em>图3-109 告警PoE行为配置界面</em></p><p><strong>表3-34 触发继电器告警配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>告警端口行为</td><td>Up-&gt;Down：端口shutdown</td></tr><tr><td>告警端口行为</td><td>Down-&gt;Up：端口down后重新up</td></tr><tr><td>告警PoE行为</td><td>Power On-&gt;Off：端口PoE下电</td></tr><tr><td>告警PoE行为</td><td>Power Off-&gt;On：端口PoE下电后重新上电</td></tr><tr><td>ID</td><td>继电器输出索引参数</td></tr><tr><td>描述</td><td>继电器输出描述符，最长支持64个字符</td></tr><tr><td>继电器强制模式</td><td>Normally-open：配置生效，继电器输出常开状态 Normally-closed：配置生效，继电器输出常闭合状态 Pulse：配置生效，继电器输出脉冲电平，周期2秒，占空比50% Off：功能关闭 默认为Off模式，配置强制模式后继电器不受告警触发控制</td></tr><tr><td>告警模式</td><td>Normally-open：配置生效，继电器输出为闭合状态，告警触发后为常开状态 Normally-closed：配置生效，继电器输出为常开状态，告警触发后为常闭合状态 Pulse：配置生效，继电器输出状态为常开状态，告警触发后，输出脉冲电平，默认状态下， 周期2秒，占空比50% Off：功能关闭 默认为Off模式</td></tr><tr><td>周期（秒）</td><td>继电器pulse常开/闭合周期</td></tr><tr><td>闭合状态持续时间（秒）</td><td>继电器pulse闭合状态的时间</td></tr><tr><td>触发告警条件</td><td>Ambient Temperature：当环境温度超出配置范围，触发继电器输出告警 Ambient Humidity：当环境湿度超出配置范围，触发继电器输出告警 System Temperature：当系统温度超出配置范围，触发继电器输出告警 PoE Power Overload：当PoE负载功率超出配置值时，触发继电器输出告警 PoE Voltage：当PoE芯片电压超出配置值时，触发继电器输出告警 PoE Temperature：当PoE芯片温度超出配置范围，触发继电器输出告警</td></tr><tr><td>告警端口</td><td>当端口从up变为down或从down变为up时，触发继电器告警输出</td></tr><tr><td>告警PoE</td><td>当端口PoE从上电变为下电或从下电变为上电时，触发继电器告警输出</td></tr></tbody></table><p>3.7.2.3 DI口配置</p><p>在导航栏中选择【配置】【继电器告警】【DI口配置】，进入DI口配置界面，如图3-115所示，触发端口行为配置界面如图3-116所示，触发PoE行为配置界面如图3-117所示，DI口配置参数如表3-35所示。</p><p><img src="'+np+'" alt="DI口输入配置界面"></p><p align="center"><em>图3-115 DI口输入配置界面</em></p><p><img src="'+op+'" alt="触发端口行为配置界面"></p><p align="center"><em>图3-116 触发端口行为配置界面</em></p><p><img src="'+sp+'" alt="触发PoE行为配置界面"></p><p align="center"><em>图3-117 触发PoE行为配置界面</em></p><p><strong>表3-35 DI口配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>触发端口行为</td><td>None：无动作</td></tr><tr><td>触发端口行为</td><td>Shutdown：shutdown端口，当DI告警恢复后，重新no shutdown端口</td></tr><tr><td>触发端口行为</td><td>Reboot：对up的端口，强制down，后重新自动up起来</td></tr><tr><td>触发PoE行为</td><td>None：无动作</td></tr><tr><td>触发PoE行为</td><td>Power-off：关闭端口PoE供电，当DI告警恢复后，重新使能端口PoE供电</td></tr><tr><td>触发PoE行为</td><td>Reboot：对上电的端口，强制关闭PoE供电，后重新自动使能PoE供电</td></tr><tr><td>ID</td><td>DI输入索引参数</td></tr><tr><td>描述</td><td>DI输入描述符，最长支持64个字符</td></tr><tr><td>告警模式</td><td>Low-level：低电平触发 High-level：高电平触发 Off：功能关闭 默认为Off模式</td></tr><tr><td>触发继电器ID</td><td>DI输入关联的触发继电器输出索引参数</td></tr><tr><td>触发端口</td><td>DI输入关联的端口</td></tr><tr><td>触发PoE</td><td>DI输入关联的端口PoE供电</td></tr></tbody></table><p>3.7.2.4 配置举例</p><p>案例需求：DI输入连接门禁开启/关闭的继电器，默认门禁关闭，DI输入为低电平，当门禁打开，DI输入为高电平。Relay输出连接外部LED告警灯，检测到门禁打开时，要求LED告警灯闪烁。交换机监测到DI输入告警，本地打印log，并发送log到log服务器。</p><p>步骤1：在导航栏中选择【配置】【继电器告警】，进入继电器告警界面。</p><p>步骤2：在“触发继电器报警”选择Relay 1，点击【编辑】按钮进入触发继电器报警配置界面，如图3-124所示填写参数，单击【确认】按钮完成操作。</p><p><img src="'+gp+'" alt="触发继电器报警"></p><p align="center"><em>图3-124 触发继电器报警</em></p><p>步骤3：在“DI口配置”选择DI 1，点击【编辑】按钮进入DI口配置界面，如图3-125所示填写参数，单击【确认】按钮完成操作。</p><p><img src="'+mp+'" alt="DI口"></p><p align="center"><em>图3-125 DI口</em></p><p>步骤4：单击辅助栏的【保存】按钮保存配置。</p><h2 id="环路检测" tabindex="-1">环路检测 <a class="header-anchor" href="#环路检测" aria-label="Permalink to &quot;环路检测&quot;">​</a></h2><h3 id="概述-2" tabindex="-1">概述 <a class="header-anchor" href="#概述-2" aria-label="Permalink to &quot;概述&quot;">​</a></h3><p>LOOP-DETECT是一种以太网环路检测协议，用于快速检测下联接口环路故障。如果发现故障存在，LOOP-DETECT会根据用户配置的故障处理方式，通知用户手工关闭或自动关闭相关端口，以避免因环路影响正常数据交互。</p><p>使能控制：使能控制分全局使能控制与接口使能控制，当全局使能，且接口上开启环路检测时，该接口支持环路检测功能。</p><p>违例处理：当接口上检测到环路故障，默认通过log通告用户手工处理环路故障，也可配置自动关闭端口方式。当采用自动关闭端口方式，且端口触发违例事件时，可通过等待违例超时、shutdown/no shutdown端口、违例恢复命令或重启设备等方式实现端口从违例中恢复。</p><p>指定vlan：默认情况下，当链路存在环路数据通路，忽略端口vlan属性，则认为单口环路；若需检测具体某vlan域内是否发生环路故障，可在端口上配置指定vlan，仅检测该vlan域内是否存在环路数据通路。</p><p>设备支持环路故障告警与环路故障恢复消息trap到snmp服务器，默认关闭，支持全局开启。</p><h3 id="配置环路检测" tabindex="-1">配置环路检测 <a class="header-anchor" href="#配置环路检测" aria-label="Permalink to &quot;配置环路检测&quot;">​</a></h3><p>配置步骤：</p><p>（1）在导航栏中选择【配置】【环路检测】，进入环路检测界面。此页面包含“全局配置”和“端口配置”两部分。</p><p>（2）在全局配置打开环路检测开关，配置探测间隔，开启Trap开关（可选），点击【应用】按钮完成配置，如图3-126所示，参数说明如表格3-36所示。</p><p><img src="'+cp+'" alt="环路检测全局配置界面"></p><p align="center"><em>图3-126 环路检测全局配置界面</em></p><p><strong>表3-36 环路检测全局配置参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>环路检测开关</td><td>开启/关闭环路检测功能，默认为全局关闭，端口关闭</td></tr><tr><td>探测间隔</td><td>配置环路探测时间间隔，范围5-300秒，默认5秒</td></tr><tr><td>Trap开关</td><td>开启/关闭环路故障Trap告警</td></tr></tbody></table><p>（2）点击“端口配置”下方的【批量配置】按钮或者需要配置的端口后的【编辑】按钮，进入环路检测端口配置界面，分别配置管理状态，违例处理方式，VLAN域检测，选择需要开启此功能的端口，如图3-1279所示，参数说明如表格3-37所示。</p><p><img src="'+lp+'" alt="环路检测端口配置界面"></p><p align="center"><em>图3-127 环路检测端口配置界面</em></p><p><strong>表3-37 环路检测端口参数说明</strong></p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>管理状态</td><td>Enable：开启端口的环路检测功能 Disabled：关闭端口的环路检测功能</td></tr><tr><td>违例处理方式</td><td>Alarm：环路发生时，Trap告警 Error-down：环路发生时，把环路端口shudown</td></tr><tr><td>VLAN域检测</td><td>在指定vlan域内检测是否发生数据通路环路</td></tr></tbody></table><h2 id="dns" tabindex="-1">DNS <a class="header-anchor" href="#dns" aria-label="Permalink to &quot;DNS&quot;">​</a></h2><h3 id="dns功能概述" tabindex="-1">DNS功能概述 <a class="header-anchor" href="#dns功能概述" aria-label="Permalink to &quot;DNS功能概述&quot;">​</a></h3><p>在一个TCP/IP架构的网络环境中，DNS（Domain Name System，域名系统）是一个重要且常用的系统。DNS主要的功能是将易于记忆的域名与不容易记忆的IP地址作转换。通过主机名，最终得到该主机名对应的IP地址的过程叫做域名解析（或主机名解析）。在解析域名时，可以首先采用静态域名解析的方法，如果静态域名解析不成功，再采用动态域名解析的方法。可以将常用的域名放入静态域名解析表中，这样可以提高域名解析效率。DNS的TCP和UDP端口号都是53，通常使用UDP。</p><h3 id="dns配置" tabindex="-1">DNS配置 <a class="header-anchor" href="#dns配置" aria-label="Permalink to &quot;DNS配置&quot;">​</a></h3><p>点击导航栏中【配置】【DNS】，进入DNS配置界面，该界面包含三个部分，如图3-128所示。</p><p><img src="'+hp+'" alt="DNS配置"></p><p align="center"><em>图3-128 DNS配置</em></p><p>3.9.2.1 静态域名配置</p><p>点击“静态域名”下方的【+添加】按钮，进入静态域名解析配置界面，如图3-129所示：</p><p><img src="'+Ap+'" alt="静态域名配置"></p><p align="center"><em>图3-129 静态域名配置</em></p><p>按照要求填写好参数，点击【确认】按钮即可完成配置。</p><p>交换机最多可以配置100条静态DNS表项。</p><p>3.9.2.2 动态域名配置</p><p>点击“域名后缀”下方的【+添加】按钮，进入域名后缀配置界面，如图3-130所示：</p><p><img src="'+Pp+'" alt="域名后缀配置"></p><p align="center"><em>图3-130 域名后缀配置</em></p><p>点击“域名服务器”下方的【+添加】按钮，进入域名后缀配置界面，如图3-131所示：</p><p><img src="'+Sp+'" alt="域名服务器配置"></p><p align="center"><em>图3-131 域名服务器配置</em></p><p>按照要求填写好参数，点击【确认】按钮即可完成配置。</p><p>✦ 交换机最多可以配置6个域名后缀。</p><p>✦ 当用户输入一个不包含完全限定域名（FQDN）的主机名时，系统会依次将这些域名后缀附加到主机名后面，尝试进行 DNS 解析。</p><h3 id="dns配置举例" tabindex="-1">DNS配置举例 <a class="header-anchor" href="#dns配置举例" aria-label="Permalink to &quot;DNS配置举例&quot;">​</a></h3><p>案例需求：SWITCH可以通过域名www.test.com访问IP地址为2.2.2.106的Server。</p><p>步骤1：在导航栏中选择【配置】【DNS】，进入DNS配置界面。</p><p>步骤2：点击“静态域名”下方的【添加】按钮，按照如图3-132所示填写好参数。</p><p>步骤3：单击【确认】按钮完成配置。</p><p>步骤4：单击辅助栏的【保存】按钮保存配置。</p><p><img src="'+_p+'" alt="静态域名参数配置"></p><p align="center"><em>图3-132 静态域名参数配置</em></p>',883)])])}const Cp=p(bp,[["render",Ep]]);export{Vp as __pageData,Cp as default};
